import React, { Suspense } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider } from '@/contexts/ThemeContext';
import { LanguageProvider } from '@/contexts/LanguageContext';
import { Toaster } from '@/components/ui/toaster';
import { ProtectedRoute } from '@/components/auth/ProtectedRoute';
import { LoadingOverlay } from '@/components/ui/loading-components';
import { VoiceChatbot } from '@/components/VoiceChatbot';

import { PageTransition } from '@/components/layout/PageTransition';
import Layout from '@/components/Layout';
import { Outlet } from 'react-router-dom';

// Lazy loaded routes
const Dashboard = React.lazy(() => import('@/pages/Dashboard'));
const CropDetails = React.lazy(() => import('@/pages/CropDetails'));
const MyFarm = React.lazy(() => import('@/pages/MyFarm'));
const MarketPrices = React.lazy(() => import('@/pages/MarketPrices'));
const GovSchemes = React.lazy(() => import('@/pages/GovSchemes'));
const AirAgent = React.lazy(() => import('@/pages/AirAgent'));
const Community = React.lazy(() => import('@/pages/Community'));
const Profile = React.lazy(() => import('@/pages/Profile'));
const Weather = React.lazy(() => import('@/pages/Weather'));
const Auth = React.lazy(() => import('@/pages/Auth'));
const ForgotPassword = React.lazy(() => import('@/pages/ForgotPassword'));
const ResetPassword = React.lazy(() => import('@/pages/ResetPassword'));
const Home = React.lazy(() => import('@/pages/Home'));
const PostDetail = React.lazy(() => import('./pages/PostDetail'));
const NotFound = React.lazy(() => import('@/pages/NotFound'));
const Crops = React.lazy(() => import('@/pages/Crops'));
const SoilAnalysis = React.lazy(() => import('@/pages/SoilAnalysis'));
const Onboarding = React.lazy(() => import('@/pages/Onboarding'));
const OnboardingCheck = React.lazy(() => import('@/pages/OnboardingCheck'));
const MessagesPage = React.lazy(() => import('@/pages/MessagesPage'));
const ChatPage = React.lazy(() => import('@/pages/ChatPage'));
const PublicProfile = React.lazy(() => import('@/pages/PublicProfile'));
const FollowersPage = React.lazy(() => import('@/pages/FollowersPage'));
const FollowingPage = React.lazy(() => import('@/pages/FollowingPage'));
import { ErrorBoundary } from '@/components/ErrorBoundary';

const MainLayout = () => {
  return (
    <Layout>
      <PageTransition>
        <Outlet />
      </PageTransition>
    </Layout>
  );
};

import { ClerkProvider } from '@clerk/clerk-react';
import { RouteGuard } from '@/components/auth/RouteGuard';
import { dark } from '@clerk/themes';

const PUBLISHABLE_KEY = import.meta.env.VITE_CLERK_PUBLISHABLE_KEY;

if (!PUBLISHABLE_KEY) {
  console.error("Missing Publishable Key");
}

import { AppLoader } from '@/components/AppLoader';
import { startKeepAlive } from '@/lib/keepAlive';

startKeepAlive(); // Ping the server to keep it awake on Render

function App() {
  return (
    <AppLoader>
      <ClerkProvider 
        publishableKey={PUBLISHABLE_KEY}
        appearance={{ baseTheme: dark }}
        signInFallbackRedirectUrl="/onboarding-check"
        signUpFallbackRedirectUrl="/onboarding"
      >
        <ThemeProvider>
          <Router>
            <LanguageProvider>
              <ErrorBoundary>
                <Suspense fallback={<LoadingOverlay message="Loading Agri Compass..." transparent />}>
                  <Routes>
                  {/* Public Routes without persistent Layout */}
                <Route path="/auth" element={<PageTransition><Auth /></PageTransition>} />
                <Route path="/forgot-password" element={<PageTransition><ForgotPassword /></PageTransition>} />
                <Route path="/reset-password" element={<PageTransition><ResetPassword /></PageTransition>} />

                {/* Onboarding Routes */}
                <Route path="/onboarding" element={<PageTransition><Onboarding /></PageTransition>} />
                <Route path="/onboarding-check" element={<PageTransition><OnboardingCheck /></PageTransition>} />

                {/* Protected Routes wrapped in persistent Layout */}
                <Route element={
                  <RouteGuard>
                    <MainLayout />
                  </RouteGuard>
                }>
                  <Route path="/" element={<Community />} />
                  <Route path="/community" element={<Community />} />
                  <Route path="/home" element={<Home />} />
                  <Route path="/dashboard" element={<Dashboard />} />
                  <Route path="/crop/:cropName" element={<CropDetails />} />
                  <Route path="/my-farm" element={<MyFarm />} />
                  <Route path="/market-prices" element={<MarketPrices />} />
                  <Route path="/schemes" element={<GovSchemes />} />
                  <Route path="/air-agent" element={<AirAgent />} />
                  <Route path="/profile" element={<Profile />} />
                  <Route path="/weather" element={<Weather />} />
                  <Route path="/post/:id" element={<PostDetail />} />
                  <Route path="/crops" element={<Crops />} />
                  <Route path="/soil-analysis" element={<SoilAnalysis />} />
                  <Route path="/messages" element={<MessagesPage />} />
                  <Route path="/messages/:userId" element={<ChatPage />} />
                  <Route path="/profile/:userId" element={<PublicProfile />} />
                  <Route path="/profile/:userId/followers" element={<FollowersPage />} />
                  <Route path="/profile/:userId/following" element={<FollowingPage />} />
                  <Route path="*" element={<NotFound />} />
                </Route>
                </Routes>
              </Suspense>
            </ErrorBoundary>
            <Toaster />
            <VoiceChatbot />
          </LanguageProvider>
        </Router>
      </ThemeProvider>
    </ClerkProvider>
    </AppLoader>
  );
}

export default App;

import { useState, useRef, useEffect, useCallback } from 'react'
import { useUser, MOCK_USERS } from '@/store';
import { AIAPI } from '@/lib/api/ai'
import { FarmsAPI, Farm } from '@/lib/api/farms'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { useToast } from '@/hooks/use-toast'
import { Send, RefreshCw, Sparkles, MessageSquare, Loader2 } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'

interface ChatMessage {
  id: string
  role: 'user' | 'assistant'
  content: string
  timestamp: Date
  isTyping?: boolean
  error?: boolean
}

interface AIChatInterfaceProps {
  selectedFarmId?: string
  onFarmSelect?: (farmId: string) => void
}

export default function AIChatInterface({ selectedFarmId, onFarmSelect }: AIChatInterfaceProps) {
  const { user } = useUser()
  const { toast } = useToast()
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [input, setInput] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [farms, setFarms] = useState<Farm[]>([])
  const [currentFarmId, setCurrentFarmId] = useState<string>(selectedFarmId || '')
  const messagesEndRef = useRef<HTMLDivElement>(null)

  const loadFarms = useCallback(async () => {
    try {
      const userFarms = await FarmsAPI.getFarms(user?.id || '')
      setFarms(userFarms)
    } catch (error) {
      console.error('Error loading farms:', error)
    }
  }, [user?.id])

  useEffect(() => {
    if (user) {
      loadFarms()
    }
  }, [user, loadFarms])

  useEffect(() => {
    if (selectedFarmId) {
      setCurrentFarmId(selectedFarmId)
    }
  }, [selectedFarmId])

  useEffect(() => {
    scrollToBottom()
  }, [messages])

  // `loadFarms` is defined above with useCallback; avoid redeclaration here.

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }

  const sendMessage = async () => {
    const trimmedInput = input.trim()
    if (!trimmedInput || isLoading || !user) return

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: trimmedInput,
      timestamp: new Date()
    }

    setMessages(prev => [...prev, userMessage])
    setInput('')
    setIsLoading(true)

    try {
      const response = await AIAPI.sendChatMessage({
        user_id: user.id,
        message: trimmedInput,
        farm_id: currentFarmId || undefined
      })

      const assistantMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response.response,
        timestamp: new Date(),
        error: !response.success
      }

      setMessages(prev => [...prev, assistantMessage])

      if (!response.success) {
        toast({
          title: 'AI Response Error',
          description: 'The AI service encountered an issue. You can try again.',
          variant: 'destructive',
        })
      }

    } catch (error) {
      console.error('Chat error:', error)

      const errorMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: 'Sorry, I\'m having trouble connecting right now. Please try again in a moment.',
        timestamp: new Date(),
        error: true
      }

      setMessages(prev => [...prev, errorMessage])

      toast({
        title: 'Connection Error',
        description: 'Unable to connect to AI service. Please check your connection and try again.',
        variant: 'destructive',
      })
    } finally {
      setIsLoading(false)
    }
  }

  const retryLastMessage = async () => {
    const lastUserMessage = [...messages].reverse().find(msg => msg.role === 'user')
    if (!lastUserMessage || isLoading) return

    // Remove error messages after the last user message
    const lastUserIndex = messages.lastIndexOf(lastUserMessage)
    const messagesToKeep = messages.slice(0, lastUserIndex + 1)
    setMessages(messagesToKeep)

    setIsLoading(true)

    try {
      const response = await AIAPI.sendChatMessage({
        user_id: user?.id || '',
        message: lastUserMessage.content,
        farm_id: currentFarmId || undefined
      })

      const assistantMessage: ChatMessage = {
        id: Date.now().toString(),
        role: 'assistant',
        content: response.response,
        timestamp: new Date(),
        error: !response.success
      }

      setMessages(prev => [...prev, assistantMessage])

    } catch (error) {
      console.error('Retry error:', error)
      const errorMessage: ChatMessage = {
        id: Date.now().toString(),
        role: 'assistant',
        content: 'Sorry, I\'m still having trouble connecting. Please try again later.',
        timestamp: new Date(),
        error: true
      }

      setMessages(prev => [...prev, errorMessage])
    } finally {
      setIsLoading(false)
    }
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      sendMessage()
    }
  }

  const handleFarmChange = (farmId: string) => {
    const idToSet = farmId === 'general' ? '' : farmId
    setCurrentFarmId(idToSet)
    onFarmSelect?.(idToSet)
  }

  const formatTime = (date: Date) => {
    return date.toLocaleTimeString('en-IN', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: true
    })
  }

  return (
    <Card className="h-[600px] flex flex-col">
      <CardHeader className="border-b">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2">
            <Sparkles className="h-5 w-5 text-green-600" />
            AI Assistant
          </CardTitle>

          {farms.length > 0 && (
            <Select value={currentFarmId || 'general'} onValueChange={handleFarmChange}>
              <SelectTrigger className="w-48">
                <SelectValue placeholder="Select farm context" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="general">General Advice</SelectItem>
                {farms.map((farm) => (
                  <SelectItem key={farm.id} value={farm.id}>
                    {farm.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}
        </div>
      </CardHeader>

      <CardContent className="flex-1 flex flex-col p-0">
        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-center text-gray-500">
              <MessageSquare className="h-12 w-12 mb-4 opacity-50" />
              <p className="text-lg font-medium mb-2">Start a conversation</p>
              <p className="text-sm">Ask me about crops, weather, or farming advice</p>
              {currentFarmId && (
                <p className="text-xs mt-2 text-green-600">
                  💡 I'll consider your farm context in my responses
                </p>
              )}
            </div>
          ) : (
            <AnimatePresence>
              {messages.map((message) => (
                <motion.div
                  key={message.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div
                    className={`max-w-[80%] rounded-lg px-4 py-3 ${
                      message.role === 'user'
                        ? 'bg-green-600 text-white'
                        : message.error
                        ? 'bg-red-50 border border-red-200 text-red-800'
                        : 'bg-gray-100 text-gray-800'
                    }`}
                  >
                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                    <p className="text-xs opacity-70 mt-2">
                      {formatTime(message.timestamp)}
                    </p>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>
          )}

          {/* Loading indicator */}
          {isLoading && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="flex justify-start"
            >
              <div className="bg-gray-100 rounded-lg px-4 py-3 max-w-[80%]">
                <div className="flex items-center gap-2 text-gray-600">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  <span className="text-sm">AI is thinking...</span>
                </div>
              </div>
            </motion.div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="border-t p-4">
          <div className="flex gap-2">
            <Input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Ask about crops, weather, or farming advice..."
              disabled={isLoading}
              className="flex-1"
            />

            <Button
              onClick={sendMessage}
              disabled={isLoading || !input.trim()}
              className="bg-green-600 hover:bg-green-700"
            >
              {isLoading ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Send className="h-4 w-4" />
              )}
            </Button>

            {/* Retry button for errors */}
            {messages.some(msg => msg.error) && !isLoading && (
              <Button
                onClick={retryLastMessage}
                variant="outline"
                size="icon"
                title="Retry last message"
              >
                <RefreshCw className="h-4 w-4" />
              </Button>
            )}
          </div>

          {currentFarmId && (
            <p className="text-xs text-gray-500 mt-2">
              💡 AI responses will consider your farm's context
            </p>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

import { useState, useEffect } from "react";

const BACKEND_URL = import.meta.env.VITE_API_BASE_URL ?? "";

export const AppLoader = ({ children }: { children: React.ReactNode }) => {
  const [backendReady, setBackendReady] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [timedOut, setTimedOut] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => setElapsed(e => e + 1), 1000);

    const checkBackend = async () => {
      const maxAttempts = 30; // 30 seconds max
      for (let i = 0; i < maxAttempts; i++) {
        try {
          const res = await fetch(`${BACKEND_URL}/api/health`, { signal: AbortSignal.timeout(3000) });
          if (res.ok) { setBackendReady(true); clearInterval(timer); return; }
        } catch (e) {
          // ignore
        }
        await new Promise(r => setTimeout(r, 1000));
      }
      setTimedOut(true);
      clearInterval(timer);
    };

    checkBackend();
    return () => clearInterval(timer);
  }, []);

  if (backendReady) return <>{children}</>;

  return (
    <div className="min-h-screen bg-[#0A0A0A] flex flex-col items-center justify-center px-6">
      <div className="text-4xl mb-6 animate-pulse">🌾</div>
      <h1 className="text-[#C9A84C] font-serif text-xl mb-2">Agri Compass</h1>

      {timedOut ? (
        <>
          <p className="text-[#F5F0E8]/40 text-sm text-center mb-4">
            Server is taking longer than usual. Please check your connection.
          </p>
          <button
            onClick={() => window.location.reload()}
            className="px-5 py-2.5 bg-[#C9A84C] text-[#0A0A0A] font-semibold rounded-lg text-sm">
            Retry
          </button>
        </>
      ) : (
        <>
          <p className="text-[#F5F0E8]/40 text-sm text-center mb-4">
            {elapsed < 5
              ? "Starting up..."
              : elapsed < 15
              ? "Waking up the server..."
              : "Almost ready, please wait..."}
          </p>
          <div className="w-48 h-1 bg-[#1E1E1E] rounded-full overflow-hidden">
            <div
              className="h-full bg-[#C9A84C] rounded-full transition-all duration-1000"
              style={{ width: `${Math.min((elapsed / 30) * 100, 95)}%` }}
            />
          </div>
          <p className="text-[#F5F0E8]/20 text-xs mt-3">{elapsed}s</p>
        </>
      )}
    </div>
  );
};

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Server, Database, BrainCircuit, Globe, ArrowRight, X } from 'lucide-react';

interface TechNode {
  id: string;
  title: string;
  icon: React.ElementType;
  description: string;
  details: string[];
  color: string;
}

const nodes: TechNode[] = [
  {
    id: 'frontend',
    title: 'Frontend Client',
    icon: Globe,
    description: 'React + TypeScript SPA built with Vite.',
    details: [
      'Tailwind CSS for responsive, utility-first styling.',
      'Framer Motion for smooth animations and transitions.',
      'Axios/Fetch for API communication with Spring Boot.',
      'Clerk for secure frontend authentication.'
    ],
    color: 'bg-blue-500'
  },
  {
    id: 'backend',
    title: 'Spring Boot API',
    icon: Server,
    description: 'Java REST API handling business logic.',
    details: [
      'Spring Boot 3 + Java 17 for robust enterprise backend.',
      'Spring Security + OAuth2 for verifying Clerk JWT tokens.',
      'JPA/Hibernate for object-relational mapping.',
      'Multipart file upload handling for media integration.'
    ],
    color: 'bg-green-600'
  },
  {
    id: 'database',
    title: 'Database Layer',
    icon: Database,
    description: 'Relational storage for app data.',
    details: [
      'SQLite database for fast, file-based persistence.',
      'Stores Users, Posts, Farms, and Comment entities.',
      'Automated schema generation via Hibernate.'
    ],
    color: 'bg-indigo-500'
  },
  {
    id: 'ai',
    title: 'AI Services',
    icon: BrainCircuit,
    description: 'Deep thought and intelligence integration.',
    details: [
      'Provides smart suggestions for crop management.',
      'Integrates via REST or external APIs (e.g., OpenAI/Local LLM).',
      'Helps farmers with predictive insights based on location.'
    ],
    color: 'bg-purple-500'
  }
];

export default function ArchitectureMap() {
  const [selectedNode, setSelectedNode] = useState<TechNode | null>(null);

  return (
    <div className="w-full flex flex-col items-center py-6 bg-slate-50/50 rounded-xl border border-slate-100 shadow-sm">
      <div className="text-center mb-10">
        <h2 className="text-2xl font-bold bg-gradient-to-r from-emerald-600 to-green-700 bg-clip-text text-transparent">
          Project Architecture
        </h2>
        <p className="text-slate-500 text-sm mt-2 max-w-lg mx-auto">
          Click on any component to understand its role and technology choices in the stack.
        </p>
      </div>

      <div className="relative w-full max-w-4xl flex flex-col md:flex-row items-center justify-between gap-6 px-4">
        {/* Frontend -> Backend */}
        <div className="hidden md:flex absolute top-1/2 left-[20%] w-[15%] h-0.5 bg-gradient-to-r from-blue-300 to-green-300 -translate-y-1/2 z-0">
          <motion.div
            className="w-2 h-2 rounded-full bg-blue-500 absolute -top-[3px] left-0"
            animate={{ left: ['0%', '100%'] }}
            transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
          />
        </div>

        {/* Backend -> DB */}
        <div className="hidden md:flex absolute top-1/2 left-[50%] w-[15%] h-0.5 bg-gradient-to-r from-green-300 to-indigo-300 -translate-y-1/2 z-0">
          <motion.div
            className="w-2 h-2 rounded-full bg-green-500 absolute -top-[3px] left-0"
            animate={{ left: ['0%', '100%'] }}
            transition={{ duration: 1.5, repeat: Infinity, ease: "linear", delay: 0.5 }}
          />
        </div>

        {/* Backend -> AI */}
        <div className="hidden md:flex absolute top-[10%] left-[50%] w-0.5 h-[30%] bg-gradient-to-b from-purple-300 to-green-300 z-0">
          <motion.div
            className="w-2 h-2 rounded-full bg-purple-500 absolute left-[calc(50%-4px)] top-0"
            animate={{ top: ['0%', '100%'] }}
            transition={{ duration: 1.5, repeat: Infinity, ease: "linear", delay: 1 }}
          />
        </div>

        {nodes.map((node, i) => {
          const Icon = node.icon;
          const isSelected = selectedNode?.id === node.id;

          return (
            <motion.div
              key={node.id}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setSelectedNode(node)}
              className={`relative z-10 flex flex-col items-center justify-center p-6 rounded-2xl cursor-pointer w-44 transition-all duration-300 ${
                isSelected 
                  ? 'bg-white shadow-xl ring-2 ring-emerald-500 ring-offset-2' 
                  : 'bg-white shadow-md hover:shadow-lg border border-slate-100'
              } ${node.id === 'ai' ? 'md:absolute md:top-[-80px] md:left-[50%] md:-translate-x-1/2' : ''}`}
            >
              <div className={`p-4 rounded-xl text-white block mb-3 shadow-inner ${node.color}`}>
                <Icon size={32} strokeWidth={1.5} />
              </div>
              <h3 className="font-semibold text-slate-800 text-center">{node.title}</h3>
              <p className="text-xs text-slate-500 text-center mt-1">{node.description}</p>
            </motion.div>
          );
        })}
      </div>

      {/* Details Modal */}
      <AnimatePresence>
        {selectedNode && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="w-full max-w-2xl mt-16 bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100 z-20"
          >
            <div className={`h-2 w-full ${selectedNode.color}`} />
            <div className="p-6 relative">
              <button 
                onClick={() => setSelectedNode(null)}
                className="absolute top-4 right-4 p-2 rounded-full hover:bg-slate-100 transition-colors text-slate-400 hover:text-slate-600"
              >
                <X size={20} />
              </button>

              <div className="flex items-center gap-4 mb-4">
                <div className={`p-3 rounded-xl text-white ${selectedNode.color}`}>
                  <selectedNode.icon size={24} />
                </div>
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{selectedNode.title}</h3>
                  <p className="text-sm border-l-2 border-emerald-500 pl-2 text-slate-600 mt-1">
                    {selectedNode.description}
                  </p>
                </div>
              </div>

              <div className="space-y-3 mt-6">
                <h4 className="text-sm font-semibold text-slate-800 uppercase tracking-wider">Implementation Details</h4>
                <ul className="space-y-2">
                  {selectedNode.details.map((detail, idx) => (
                    <motion.li 
                      key={idx}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: idx * 0.1 }}
                      className="flex items-start gap-3 text-sm text-slate-600 bg-slate-50 p-3 rounded-lg border border-slate-100"
                    >
                      <ArrowRight size={16} className={`mt-0.5 shrink-0 ${selectedNode.color.replace('bg-', 'text-')}`} />
                      {detail}
                    </motion.li>
                  ))}
                </ul>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useUser, MOCK_USERS } from '@/store';
import { PostsAPI, Comment } from '@/lib/api/posts'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar'
import { useToast } from '@/hooks/use-toast'
import { MessageCircle, Send } from 'lucide-react'
import { format } from 'date-fns'

interface CommentSectionProps {
  postId: string
  commentsCount: number
  onCommentsCountChange: (count: number) => void
}

export default function CommentSection({ postId, commentsCount, onCommentsCountChange }: CommentSectionProps) {
  const { user } = useUser()
  const { toast } = useToast()
  const navigate = useNavigate()
  const [comments, setComments] = useState<Comment[]>([])
  const [newComment, setNewComment] = useState('')
  const [isExpanded, setIsExpanded] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)

  useEffect(() => {
    if (isExpanded && comments.length === 0) {
      loadComments()
    }
  }, [isExpanded, comments.length])

  const loadComments = async () => {
    try {
      setIsLoading(true)
      const data = await PostsAPI.getComments(postId)
      setComments(data)
    } catch (error) {
      console.error('Error loading comments:', error)
      toast({
        title: 'Error loading comments',
        description: 'Failed to load comments',
        variant: 'destructive',
      })
    } finally {
      setIsLoading(false)
    }
  }

  const handleSubmitComment = async () => {
    if (!newComment.trim() || !user) return

    try {
      setIsSubmitting(true)
      const comment = await PostsAPI.addComment(postId, user.id, newComment.trim())
      setComments(prev => [...prev, comment])
      setNewComment('')
      onCommentsCountChange(commentsCount + 1)

      toast({
        title: 'Comment added!',
        description: 'Your comment has been posted.',
      })
    } catch (error) {
      console.error('Error adding comment:', error)
      toast({
        title: 'Error adding comment',
        description: 'Failed to add your comment',
        variant: 'destructive',
      })
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmitComment()
    }
  }

  return (
    <div className="space-y-4">
      {/* Comment Toggle Button */}
      <Button
        variant="ghost"
        size="sm"
        onClick={() => setIsExpanded(!isExpanded)}
        className="flex items-center gap-2 text-gray-600 hover:text-gray-800"
      >
        <MessageCircle className="h-4 w-4" />
        {commentsCount} {commentsCount === 1 ? 'comment' : 'comments'}
        {isExpanded ? ' (hide)' : ' (show)'}
      </Button>

      {/* Comments List */}
      {isExpanded && (
        <div className="space-y-4">
          {isLoading ? (
            <div className="text-center py-4">
              <div className="animate-spin h-6 w-6 border-2 border-green-600 border-t-transparent rounded-full mx-auto"></div>
              <p className="text-sm text-gray-500 mt-2">Loading comments...</p>
            </div>
          ) : (
            <>
              {comments.map((comment) => (
                <div key={comment.id} className="flex gap-3 p-3 bg-gray-50 rounded-lg">
                  <Avatar 
                    className="h-8 w-8 cursor-pointer hover:opacity-80 transition-opacity" 
                    onClick={() => navigate(`/profile/${comment.user.id}`)}
                  >
                    <AvatarImage src={comment.user.avatar_url} />
                    <AvatarFallback>
                      {comment.user.username[0].toUpperCase()}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="font-medium text-sm">
                        {comment.user.full_name || comment.user.username}
                      </span>
                      <span className="text-xs text-gray-500">
                        {format(new Date(comment.created_at), 'MMM d, yyyy')}
                      </span>
                    </div>
                    <p className="text-sm text-gray-800 whitespace-pre-wrap">
                      {comment.content}
                    </p>
                  </div>
                </div>
              ))}

              {comments.length === 0 && (
                <div className="text-center py-6 text-gray-500">
                  <MessageCircle className="h-8 w-8 mx-auto mb-2 opacity-50" />
                  <p className="text-sm">No comments yet. Be the first to comment!</p>
                </div>
              )}
            </>
          )}

          {/* Add Comment */}
          {user && (
            <div className="flex gap-3">
              <Avatar 
                className="h-8 w-8 cursor-pointer hover:opacity-80 transition-opacity"
                onClick={() => navigate(`/profile/${user?.id}`)}
              >
                <AvatarImage src={user.user_metadata?.avatar_url} />
                <AvatarFallback>
                  {user.email?.[0].toUpperCase() || 'U'}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 space-y-2">
                <Textarea
                  placeholder="Write a comment..."
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  onKeyPress={handleKeyPress}
                  className="min-h-[80px] resize-none"
                  disabled={isSubmitting}
                />
                <div className="flex justify-end">
                  <Button
                    onClick={handleSubmitComment}
                    disabled={!newComment.trim() || isSubmitting}
                    size="sm"
                    className="flex items-center gap-2"
                  >
                    {isSubmitting ? (
                      <>
                        <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div>
                        Posting...
                      </>
                    ) : (
                      <>
                        <Send className="h-4 w-4" />
                        Comment
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useUser, MOCK_USERS } from '@/store';
import { PostsAPI } from '@/lib/api/posts'
import { FarmsAPI } from '@/lib/api/farms'
import { UploadAPI } from '@/lib/api/upload'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { useToast } from '@/hooks/use-toast'
import { X, Upload, MapPin, Sprout } from 'lucide-react'
import { useDropzone } from 'react-dropzone'

interface CreatePostModalProps {
  isOpen: boolean
  onClose: () => void
  onPostCreated?: () => void
}

interface Farm {
  id: string
  name: string
  crop_type?: string
  location?: string
}

export default function CreatePostModal({ isOpen, onClose, onPostCreated }: CreatePostModalProps) {
  const { user } = useUser()
  const { toast } = useToast()
  const [title, setTitle] = useState('')
  const [content, setContent] = useState('')
  const [cropTags, setCropTags] = useState<string[]>([])
  const [location, setLocation] = useState('')
  const [selectedFarmId, setSelectedFarmId] = useState('')
  const [mediaFiles, setMediaFiles] = useState<File[]>([])
  const [previewUrls, setPreviewUrls] = useState<string[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [farms, setFarms] = useState<Farm[]>([])
  const [loadingFarms, setLoadingFarms] = useState(false)

  const { getRootProps, getInputProps } = useDropzone({
    accept: {
      'image/*': ['.png', '.jpg', '.jpeg', '.gif']
    },
    maxFiles: 6,
    onDrop: (acceptedFiles: File[]) => {
      const newFiles = [...mediaFiles, ...acceptedFiles].slice(0, 6)
      setMediaFiles(newFiles)

      // Create preview URLs
      const newPreviewUrls = newFiles.map(file => URL.createObjectURL(file))
      setPreviewUrls(newPreviewUrls)
    }
  })

  useEffect(() => {
    let isMounted = true;
    if (isOpen && user) {
      loadUserFarms(isMounted)
    }
    return () => { isMounted = false; }
  }, [isOpen, user])

  useEffect(() => {
    // Cleanup preview URLs on unmount
    return () => {
      previewUrls.forEach(url => URL.revokeObjectURL(url))
    }
  }, [previewUrls])

  const loadUserFarms = async (isMounted: boolean) => {
    if (!user) return

    setLoadingFarms(true)
    try {
      const data = await FarmsAPI.getFarms(user.id)
      if (isMounted) setFarms(data || [])
    } catch (error) {
      console.error('Error loading farms:', error)
    } finally {
      if (isMounted) setLoadingFarms(false)
    }
  }

  const handleCropTagAdd = (tag: string) => {
    if (tag && !cropTags.includes(tag)) {
      setCropTags([...cropTags, tag])
    }
  }

  const handleCropTagRemove = (tagToRemove: string) => {
    setCropTags(cropTags.filter(tag => tag !== tagToRemove))
  }

  const handleRemoveImage = (index: number) => {
    const newFiles = mediaFiles.filter((_, i) => i !== index)
    const newPreviewUrls = previewUrls.filter((_, i) => i !== index)
    setMediaFiles(newFiles)
    setPreviewUrls(newPreviewUrls)
  }

  const handleSubmit = async () => {
    if (!content.trim()) {
      toast({
        title: 'Content required',
        description: 'Please write something for your post',
        variant: 'destructive'
      })
      return
    }

    setIsLoading(true)
    let success = false;
    try {
      // Upload images if any
      const imageUrls: string[] = []
      if (mediaFiles.length > 0) {
        toast({ title: 'Uploading images...' })
        const urls = await UploadAPI.uploadMultipleMedia(mediaFiles, 'posts')
        imageUrls.push(...urls)
      }

      // Create post
      await PostsAPI.createPost({
        user_id: user?.id || '',
        title: title.trim() || undefined,
        body: content,
        crop_tags: cropTags.length > 0 ? cropTags : undefined,
        location: location.trim() || undefined,
        images: imageUrls.length > 0 ? imageUrls : undefined,
        farm_id: selectedFarmId || undefined,
      })

      // Reset form
      previewUrls.forEach(url => URL.revokeObjectURL(url))
      setTitle('')
      setContent('')
      setCropTags([])
      setLocation('')
      setSelectedFarmId('')
      setMediaFiles([])
      setPreviewUrls([])

      success = true;

      toast({
        title: 'Post created successfully!',
        description: 'Your post is now visible to the community'
      })
    } catch (error) {
      console.error('Error creating post:', error)
      const msg = (error as Record<string, unknown>)?.message as string ?? String(error)
      toast({
        title: 'Error creating post',
        description: msg || 'Please try again later',
        variant: 'destructive'
      })
    } finally {
      setIsLoading(false)
      if (success) {
        onPostCreated?.()
        onClose()
      }
    }
  }

  const handleFarmSelect = (farmId: string) => {
    setSelectedFarmId(farmId)
    const selectedFarm = farms.find(f => f.id === farmId)
    if (selectedFarm) {
      // Auto-fill crop tags and location from selected farm
      if (selectedFarm.crop_type && !cropTags.includes(selectedFarm.crop_type)) {
        setCropTags([...cropTags, selectedFarm.crop_type])
      }
      if (selectedFarm.location && !location) {
        setLocation(selectedFarm.location)
      }
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Create New Post</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {/* Title */}
          <div>
            <Input
              placeholder="Post title (optional)"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full"
            />
          </div>

          {/* Content */}
          <div>
            <Textarea
              placeholder="What's on your mind?"
              value={content}
              onChange={(e) => setContent(e.target.value)}
              className="min-h-[120px] w-full"
              required
            />
          </div>

          {/* Farm Selection */}
          <div>
            <label className="text-sm font-medium mb-2 block">Link to your farm (optional)</label>
            <Select value={selectedFarmId} onValueChange={handleFarmSelect} disabled={loadingFarms}>
              <SelectTrigger>
                <SelectValue placeholder={loadingFarms ? "Loading farms..." : "Select a farm"} />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">No farm selected</SelectItem>
                {farms.map((farm) => (
                  <SelectItem key={farm.id} value={farm.id}>
                    {farm.name} {farm.crop_type && `(${farm.crop_type})`}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Crop Tags */}
          <div>
            <label className="text-sm font-medium mb-2 block">Related crops</label>
            <div className="flex flex-wrap gap-2 mb-2">
              {cropTags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-2 py-1 bg-green-100 text-green-800 rounded-full text-sm"
                >
                  <Sprout className="h-3 w-3" />
                  {tag}
                  <button
                    type="button"
                    onClick={() => handleCropTagRemove(tag)}
                    className="ml-1 hover:bg-green-200 rounded-full p-0.5"
                    aria-label={`Remove ${tag} tag`}
                  >
                    <X className="h-3 w-3" />
                  </button>
                </span>
              ))}
            </div>
            <Input
              placeholder="Add crop (press Enter)"
              onKeyPress={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault()
                  const input = e.target as HTMLInputElement
                  handleCropTagAdd(input.value.trim())
                  input.value = ''
                }
              }}
            />
          </div>

          {/* Location */}
          <div>
            <label className="text-sm font-medium mb-2 block">Location</label>
            <div className="relative">
              <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Where is this post about?"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="pl-10"
              />
            </div>
          </div>

          {/* Image Upload */}
          <div>
            <label className="text-sm font-medium mb-2 block">Images (max 6)</label>
            <div
              {...getRootProps()}
              className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center cursor-pointer hover:border-green-400 hover:bg-green-50 transition-colors"
            >
              <input {...getInputProps()} />
              <div className="flex flex-col items-center gap-2">
                <Upload className="h-8 w-8 text-gray-400" />
                <p className="text-sm text-gray-600">
                  Drop images here or click to upload
                </p>
                <p className="text-xs text-gray-500">
                  PNG, JPG, JPEG, GIF up to 6 files
                </p>
              </div>
            </div>

            {/* Image Previews */}
            {previewUrls.length > 0 && (
              <div className="grid grid-cols-3 gap-2 mt-4">
                {previewUrls.map((url, index) => (
                  <div key={url} className="relative group">
                    <img
                      src={url}
                      alt={`Preview ${index + 1}`}
                      className="w-full h-20 object-cover rounded-lg"
                    />
                    <button
                      onClick={() => handleRemoveImage(index)}
                      className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Submit Button */}
          <div className="flex justify-end gap-2 pt-4">
            <Button variant="outline" onClick={onClose} disabled={isLoading}>
              Cancel
            </Button>
            <Button onClick={handleSubmit} disabled={isLoading || !content.trim()}>
              {isLoading ? 'Creating...' : 'Create Post'}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  )
}

import { Component, ErrorInfo, ReactNode } from 'react';
import { Button } from '@/components/ui/button';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
  errorInfo?: ErrorInfo;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('ErrorBoundary caught an error:', error, errorInfo);

    // Auto-reload on chunk load error (common after new deployments)
    if (
      error.name === 'ChunkLoadError' ||
      error.message.includes('Failed to fetch dynamically imported module') ||
      error.message.includes('dynamically imported module') ||
      error.message.includes('Failed to load module script') ||
      error.message.includes('application/octet-stream')
    ) {
      // Force a hard reload from server
      window.location.reload();
      return;
    }

    this.setState({
      error,
      errorInfo,
    });

    // Log to error reporting service in production
    if (process.env.NODE_ENV === 'production') {
      // Example: Sentry, LogRocket, etc.
      // logErrorToService(error, errorInfo);
    }
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: undefined, errorInfo: undefined });
  };

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

    return (
      <div className="min-h-screen flex items-center justify-center bg-earth-main p-4" style={{ background: 'var(--bg-main)' }}>
        <div className="max-w-md w-full bg-earth-card rounded-2xl shadow-premium p-8 text-center border border-earth-border" style={{ background: 'var(--bg-card)', borderColor: 'var(--border-subtle)' }}>
          <div className="mb-6">
            <div className="h-16 w-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
              <AlertTriangle className="h-8 w-8 text-red-500" />
            </div>
            <h2 className="text-2xl font-black text-gold-100 tracking-tight mb-2">
              Something went wrong
            </h2>
            <p className="text-gold-100/40 text-sm font-medium italic mb-6">
              An unexpected error occurred. Please try again.
            </p>
          </div>

          <div className="space-y-4">
            <Button onClick={this.handleRetry} className="btn-gold w-full h-12 shadow-gold-glow">
              <RefreshCw className="h-4 w-4 mr-3" />
              Try again
            </Button>

            <Button
              variant="ghost"
              onClick={() => window.location.href = '/'}
              className="w-full text-gold-100/40 hover:text-gold-100"
            >
              Go to Dashboard
            </Button>
          </div>

          {(import.meta.env.DEV || process.env.NODE_ENV === 'development') && this.state.error && (
            <details className="mt-8 text-left border-t border-earth-border pt-6">
              <summary className="cursor-pointer text-[10px] font-black uppercase tracking-widest text-gold-100/20 hover:text-gold-400 transition-colors">
                Error Details (Dev)
              </summary>
              <pre className="mt-4 text-[10px] bg-earth-main p-4 rounded-xl overflow-auto max-h-48 text-red-400/80 border border-red-500/10 font-mono">
                {this.state.error.toString()}
                {this.state.errorInfo?.componentStack}
              </pre>
            </details>
          )}
        </div>
      </div>
    );
    }

    return this.props.children;
  }
}

/**
 * Hook for handling async errors in functional components
 */
export function useErrorHandler() {
  return (error: Error, errorInfo?: { componentStack?: string }) => {
    console.error('Async error caught:', error, errorInfo);

    // Could dispatch to error reporting service
    if (process.env.NODE_ENV === 'production') {
      // logErrorToService(error, errorInfo);
    }
  };
}

/**
 * Network Error Handler Component
 */
export function NetworkErrorHandler({
  error,
  onRetry,
  children
}: {
  error: Error | null;
  onRetry: () => void;
  children: ReactNode;
}) {
  if (error) {
    return (
      <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
        <div className="flex items-center">
          <AlertTriangle className="h-5 w-5 text-red-500 mr-2" />
          <div className="flex-1">
            <h3 className="text-sm font-medium text-red-800">
              Network Error
            </h3>
            <p className="text-sm text-red-700 mt-1">
              {error.message || 'Unable to connect. Please check your internet connection.'}
            </p>
          </div>
          <Button
            size="sm"
            variant="outline"
            onClick={onRetry}
            className="ml-3"
          >
            <RefreshCw className="h-4 w-4 mr-1" />
            Retry
          </Button>
        </div>
      </div>
    );
  }

  return <>{children}</>;
}

import { useState, useRef } from 'react'
import { useUser, MOCK_USERS } from '@/store';
import { FarmsAPI, FarmImage } from '@/lib/api/farms'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { useToast } from '@/hooks/use-toast'
import { Camera, Upload, ImageIcon } from 'lucide-react'
import { format } from 'date-fns'

interface FarmImageGalleryProps {
  farmId: string
  farmName: string
  images: FarmImage[]
  onImagesUpdate: (images: FarmImage[]) => void
  isOpen: boolean
  onClose: () => void
}

export default function FarmImageGallery({
  farmId,
  farmName,
  images,
  onImagesUpdate,
  isOpen,
  onClose
}: FarmImageGalleryProps) {
  const { user } = useUser()
  const { toast } = useToast()
  const [isUploading, setIsUploading] = useState(false)
  const [selectedImage, setSelectedImage] = useState<FarmImage | null>(null)
  const [caption, setCaption] = useState('')
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (!file || !user) return

    // Validate file type
    if (!file.type.startsWith('image/')) {
      toast({
        title: 'Invalid file type',
        description: 'Please select an image file',
        variant: 'destructive',
      })
      return
    }

    // Validate file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
      toast({
        title: 'File too large',
        description: 'Please select an image smaller than 5MB',
        variant: 'destructive',
      })
      return
    }

    try {
      setIsUploading(true)
      const uploadedImage = await FarmsAPI.uploadFarmImage(farmId, user.id, file, caption || undefined)

      toast({
        title: 'Image uploaded!',
        description: 'Your farm image has been uploaded successfully.',
      })

      onImagesUpdate([...images, uploadedImage])
      setCaption('')
      if (fileInputRef.current) {
        fileInputRef.current.value = ''
      }
    } catch (error) {
      console.error('Error uploading image:', error)
      toast({
        title: 'Upload failed',
        description: 'Failed to upload image. Please try again.',
        variant: 'destructive',
      })
    } finally {
      setIsUploading(false)
    }
  }

  const handleImageClick = (image: FarmImage) => {
    setSelectedImage(image)
  }

  const closeImageModal = () => {
    setSelectedImage(null)
  }

  return (
    <>
      <Dialog open={isOpen} onOpenChange={onClose}>
        <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
