                    className="w-full bg-[#1a1a14] border border-earth-border/60 hover:bg-earth-card text-gold-100 text-xs font-black uppercase tracking-widest py-3 rounded-xl"
                  >
                    Manage Account (Clerk)
                  </Button>
                  <Button
                    onClick={handleSignOut}
                    className="w-full bg-red-500/10 border border-red-500/20 hover:bg-red-500/20 text-red-400 text-xs font-black uppercase tracking-widest py-3 rounded-xl"
                  >
                    Sign Out
                  </Button>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* ===== MAIN CONTENT ===== */}
      <main className="flex-1 w-full z-10 relative">
        {children}
      </main>

      {/* Floating KrishiMitra Assistant */}
      <KrishiMitraFloat />

      {/* Voice Command Dialog Overlay */}
      <VoiceCommandModal isOpen={isVoiceOpen} onClose={() => setIsVoiceOpen(false)} />
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react'
import { useUser, MOCK_USERS } from '@/store';
import { PostsAPI, Notification } from '@/lib/api/posts'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from '@/components/ui/dropdown-menu'
import { Bell, Heart, MessageCircle, UserPlus, AtSign } from 'lucide-react'
import { format } from 'date-fns'

export default function NotificationBell() {
  const { user } = useUser()
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [unreadCount, setUnreadCount] = useState(0)
  const [isLoading, setIsLoading] = useState(false)

  // Stable callback so effect dependencies remain stable
  const loadNotifications = useCallback(async () => {
    if (!user) return

    try {
      setIsLoading(true)
      const data = await PostsAPI.getNotifications(user.id)
      setNotifications(data)
      setUnreadCount(data.filter(n => !n.read).length)
    } catch (error) {
      console.error('Error loading notifications:', error)
    } finally {
      setIsLoading(false)
    }
  }, [user])

  useEffect(() => {
    if (user) {
      loadNotifications()
      // Poll for new notifications every 30 seconds
      const interval = setInterval(loadNotifications, 30000)
      return () => clearInterval(interval)
    }
  }, [user, loadNotifications])

  const markAsRead = async (notificationId: string) => {
    try {
      await PostsAPI.markNotificationAsRead(notificationId)
      setNotifications(prev =>
        prev.map(n =>
          n.id === notificationId ? { ...n, read: true } : n
        )
      )
      setUnreadCount(prev => Math.max(0, prev - 1))
    } catch (error) {
      console.error('Error marking notification as read:', error)
    }
  }

  const getNotificationIcon = (type: Notification['type']) => {
    switch (type) {
      case 'like':
        return <Heart className="h-4 w-4 text-red-500" />
      case 'comment':
        return <MessageCircle className="h-4 w-4 text-blue-500" />
      case 'follow':
        return <UserPlus className="h-4 w-4 text-green-500" />
      case 'mention':
        return <AtSign className="h-4 w-4 text-purple-500" />
      default:
        return <Bell className="h-4 w-4 text-gray-500" />
    }
  }

  const getNotificationText = (notification: Notification) => {
    switch (notification.type) {
      case 'like':
        return 'liked your post'
      case 'comment':
        return 'commented on your post'
      case 'follow':
        return 'started following you'
      case 'mention':
        return 'mentioned you in a post'
      default:
        return 'sent you a notification'
    }
  }

  if (!user) return null

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge
              variant="destructive"
              className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 text-xs"
            >
              {unreadCount > 99 ? '99+' : unreadCount}
            </Badge>
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-80 max-h-96 overflow-y-auto">
        <div className="px-2 py-1.5 text-sm font-medium border-b">
          Notifications
        </div>

        {isLoading ? (
          <div className="px-2 py-4 text-center text-sm text-gray-500">
            Loading...
          </div>
        ) : notifications.length === 0 ? (
          <div className="px-2 py-4 text-center text-sm text-gray-500">
            No notifications yet
          </div>
        ) : (
          notifications.map((notification) => (
            <DropdownMenuItem
              key={notification.id}
              className={`px-2 py-3 cursor-pointer ${
                !notification.read ? 'bg-blue-50' : ''
              }`}
              onClick={() => markAsRead(notification.id)}
            >
              <div className="flex items-start gap-3 w-full">
                <div className="flex-shrink-0 mt-0.5">
                  {getNotificationIcon(notification.type)}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-gray-900">
                    Someone {getNotificationText(notification)}
                  </p>
                  <p className="text-xs text-gray-500 mt-1">
                    {format(new Date(notification.created_at), 'MMM d, h:mm a')}
                  </p>
                </div>
                {!notification.read && (
                  <div className="flex-shrink-0">
                    <div className="h-2 w-2 bg-blue-500 rounded-full"></div>
                  </div>
                )}
              </div>
            </DropdownMenuItem>
          ))
        )}

        {notifications.length > 0 && (
          <>
            <DropdownMenuSeparator />
            <div className="px-2 py-1.5">
              <Button
                variant="ghost"
                size="sm"
                className="w-full text-xs"
                onClick={() => {
                  // Mark all as read
                  notifications
                    .filter(n => !n.read)
                    .forEach(n => markAsRead(n.id))
                }}
              >
                Mark all as read
              </Button>
            </div>
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Mic, MicOff, Volume2, X, Send, Sprout } from "lucide-react";
import { useNavigate, useLocation } from "react-router-dom";
import { apiPost } from "@/lib/httpClient";

export const VoiceChatbot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [textInput, setTextInput] = useState("");
  const [response, setResponse] = useState("ಹಲೋ! ನಾನು ಕೃಷಿ ಸಹಾಯಕಿ. ನಾನು ನಿಮಗೆ ಹೇಗೆ ಸಹಾಯ ಮಾಡಬಹುದು?"); // "Hello! I am Agri Assistant. How can I help you?"
  const [isSpeaking, setIsSpeaking] = useState(false);

  const recognitionRef = useRef<any>(null);
  const navigate = useNavigate();
  const location = useLocation();

  // Hide the chatbot entirely on the messages pages to prevent overlapping the chat input
  const isMessagesPage = location.pathname.startsWith('/messages');

  useEffect(() => {
    // Check if browser supports speech recognition
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.lang = "kn-IN"; // Kannada language

      recognitionRef.current.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        setTranscript(text);
        handleIntent(text);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      setTranscript("");
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  const speak = (text: string) => {
    if (!window.speechSynthesis) return;

    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = "kn-IN";
    utterance.rate = 0.9;

    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend = () => setIsSpeaking(false);

    window.speechSynthesis.speak(utterance);
  };

  const handleIntent = async (text: string) => {
    setResponse("ವಿಶ್ಲೇಷಿಸಲಾಗುತ್ತಿದೆ..."); // "Analyzing..."

    try {
      const data = await apiPost("/api/ai/chat", {
        message: text,
        maxTokens: 150,
        systemContext: `You are a helpful agricultural assistant for farmers in Karnataka.
          The user will speak in Kannada or English. 
          Respond ONLY in Kannada script. Keep it under 2 sentences.
          If they ask about prices, suggest /market-prices.
          If they ask about weather, suggest /weather.
          If they ask about schemes, suggest /schemes.
          Format your response as: [Action]|Your Kannada response here
          Where Action is either a path (e.g. /weather) or "none".`
      });

      const rawText = data?.reply || data?.response || "";

      const [action, reply] = rawText.includes("|") ? rawText.split("|") : ["none", rawText];

      setResponse(reply.trim());
      speak(reply.trim());

      if (action !== "none" && action.startsWith("/")) {
        setTimeout(() => {
          navigate(action.trim());
          setIsOpen(false);
        }, 2000);
      }

    } catch (error) {
      console.error(error);
      const msg = "ಕ್ಷಮಿಸಿ, ದೋಷ ಉಂಟಾಗಿದೆ."; // Sorry, an error occurred
      setResponse(msg);
      speak(msg);
    }
  };

  if (isMessagesPage) return null;

  return (
    <>
      {/* Floating Action Button */}
      <motion.button
        whileHover={{ scale: 1.05, rotate: 5 }}
        whileTap={{ scale: 0.95 }}
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-[#C9A84C] text-[#0A0A0A] rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(201,168,76,0.4)] z-50 hover:bg-[#D4B86A] transition-all duration-300"
      >
        <Sprout className="w-6 h-6" />
      </motion.button>

      {/* Voice Chatbot Interface */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.9 }}
            className="fixed bottom-24 right-6 w-96 bg-[#0A0A0A]/95 backdrop-blur-2xl border border-[#1E1E1E] rounded-2xl shadow-[0_10px_40px_-10px_rgba(0,0,0,0.8)] z-50 overflow-hidden flex flex-col"
          >
            {/* Header */}
            <div className="px-5 py-4 flex items-center justify-between border-b border-[#1E1E1E] bg-[#111111]/50">
              <div className="flex items-center gap-3">
                <div className={`w-2 h-2 rounded-full ${isSpeaking ? 'bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-[#C9A84C]'}`} />
                <h3 className="text-[#F5F0E8] font-bold text-xs uppercase tracking-widest">Agri Voice Assistant</h3>
              </div>
              <button onClick={() => {
                setIsOpen(false);
                if (window.speechSynthesis) window.speechSynthesis.cancel();
              }} className="text-[#F5F0E8]/40 hover:text-[#F5F0E8] transition-colors p-1 hover:bg-[#1E1E1E] rounded-md">
                <X className="w-4 h-4" />
              </button>
            </div>

            {/* Content Area - Chat Bubbles */}
            <div className="p-5 space-y-6 flex-1 min-h-[18rem] max-h-[24rem] overflow-y-auto custom-scrollbar">

              {/* User Bubble */}
              <AnimatePresence>
                {transcript && (
                  <motion.div 
                    initial={{ opacity: 0, x: 10, scale: 0.95 }}
                    animate={{ opacity: 1, x: 0, scale: 1 }}
                    className="flex justify-end"
                  >
                    <div className="bg-[#1E1E1E] text-[#F5F0E8] px-4 py-2.5 rounded-2xl rounded-tr-sm max-w-[85%] text-sm shadow-md border border-[#2A2A2A]">
                      {transcript}
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* AI Bubble */}
              <motion.div 
                initial={{ opacity: 0, x: -10, scale: 0.95 }}
                animate={{ opacity: 1, x: 0, scale: 1 }}
                key={response}
                className="flex items-start gap-3"
              >
                <div className="w-8 h-8 rounded-full bg-[#111111] border border-[#1E1E1E] flex items-center justify-center flex-shrink-0 shadow-inner mt-1">
                  {isSpeaking ? (
                    <div className="flex items-end gap-0.5 h-3">
                      <motion.div animate={{ height: ["20%", "100%", "20%"] }} transition={{ repeat: Infinity, duration: 0.5 }} className="w-1 bg-[#C9A84C] rounded-full" />
                      <motion.div animate={{ height: ["40%", "80%", "40%"] }} transition={{ repeat: Infinity, duration: 0.6 }} className="w-1 bg-[#C9A84C] rounded-full" />
                      <motion.div animate={{ height: ["30%", "100%", "30%"] }} transition={{ repeat: Infinity, duration: 0.4 }} className="w-1 bg-[#C9A84C] rounded-full" />
                    </div>
                  ) : (
                    <Volume2 className="w-4 h-4 text-[#C9A84C]" />
                  )}
                </div>
                <div className="bg-[#111111] border border-[#C9A84C]/20 text-[#F5F0E8] px-4 py-3 rounded-2xl rounded-tl-sm max-w-[85%] text-sm shadow-[0_2px_15px_rgba(201,168,76,0.05)] leading-relaxed font-medium">
                  {response}
                </div>
              </motion.div>

            </div>

            {/* Input Area */}
            <div className="p-4 bg-[#0A0A0A] border-t border-[#1E1E1E]">
              <form 
                onSubmit={(e) => { 
                  e.preventDefault(); 
                  if (textInput.trim()) { 
                    handleIntent(textInput); 
                    setTranscript(textInput);
                    setTextInput(''); 
                  } 
                }} 
                className="flex items-center gap-2 bg-[#111111] border border-[#1E1E1E] rounded-xl p-1.5 focus-within:border-[#C9A84C]/50 transition-colors shadow-inner"
              >
                <input
                  type="text"
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  placeholder={isListening ? "Listening..." : "Ask anything..."}
                  className="flex-1 min-w-0 bg-transparent px-3 py-1.5 text-sm text-[#F5F0E8] focus:outline-none placeholder:text-[#F5F0E8]/30 font-medium"
                />
                <button
                  type="button"
                  onClick={toggleListening}
                  className={`p-2 rounded-lg transition-all flex-shrink-0 ${
                    isListening 
                      ? 'bg-red-500/20 text-red-500 animate-pulse border border-red-500/50' 
                      : 'bg-[#1E1E1E] text-[#C9A84C] hover:bg-[#2A2A2A]'
                  }`}
                  title="Speak"
                >
                  {isListening ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
                </button>
                <button
                  type="submit"
                  disabled={!textInput.trim()}
                  className="p-2 bg-[#C9A84C] text-[#0A0A0A] rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-[#D4B86A] transition-colors flex-shrink-0 shadow-sm"
                  title="Send"
                >
                  <Send className="w-4 h-4" />
                </button>
              </form>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Sparkles, Mic, MicOff } from 'lucide-react';
import SpeechRecognition, { useSpeechRecognition } from 'react-speech-recognition';
import { callGemini } from '@/lib/geminiClient';
import { Input } from '@/components/ui/input';

interface ChatWindowProps {
  compact?: boolean;
}

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

const STATIC_ANSWERS: Record<string, string> = {
  "What is PM-KISAN?":
    "PM-KISAN gives ₹6,000/year directly to farmer families in 3 instalments. Apply at your nearest Common Service Centre with Aadhaar and land records.",
  "Best crops for Kharif season?":
    "For Karnataka Kharif: Cotton, Ragi, Maize, Soybean, and Groundnut. Cotton suits Black Cotton soil districts like Bagalkot and Bidar.",
  "How to improve soil health?":
    "Apply organic matter (compost/FYM) before sowing. Test soil pH — 6.5 to 7.5 is ideal. Use Urea for nitrogen, DAP for phosphorus at planting.",
  "Cotton price today?":
    "Check the Market Prices page for live APMC rates. Current MSP for cotton is ₹6,620/quintal as set by the Government of India.",
};

export function ChatWindow({ compact = false }: ChatWindowProps) {
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'assistant',
      content: 'Namaste! I am KrishiMitra, your farming assistant. How can I help you today?',
    },
  ]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const {
    transcript,
    listening,
    resetTranscript,
    browserSupportsSpeechRecognition,
  } = useSpeechRecognition();

  useEffect(() => {
    if (transcript) {
      setInput(transcript);
    }
  }, [transcript]);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [messages, sending]);

  const handleSend = async (textToSend?: string) => {
    const query = (textToSend || input).trim();
    if (!query) return;

    const userMsg: Message = {
      id: Math.random().toString(),
      role: 'user',
      content: query,
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    resetTranscript();
    setSending(true);

    try {
      const staticReply = STATIC_ANSWERS[query];
      let replyText = '';

      if (staticReply) {
        replyText = staticReply;
      } else {
        const historyContext = messages.map(m => ({
          role: m.role,
          content: m.content,
        }));
        replyText = await callGemini(query, undefined, historyContext);
      }

      setMessages(prev => [
        ...prev,
        {
          id: Math.random().toString(),
          role: 'assistant',
          content: replyText,
        },
      ]);
    } catch (error: any) {
      setMessages(prev => [
        ...prev,
        {
          id: Math.random().toString(),
          role: 'assistant',
          content: error.message || 'I am having trouble responding right now. Please try again.',
        },
      ]);
    } finally {
      setSending(false);
    }
  };

  const toggleListening = () => {
    if (listening) {
      SpeechRecognition.stopListening();
    } else {
      resetTranscript();
      SpeechRecognition.startListening({ continuous: true });
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#1a1a14] text-[#f0ece0]">
      {/* Scrollable Message List */}
      <div 
        ref={listRef} 
        className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar text-[13px]"
      >
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-xl px-3 py-2 leading-relaxed shadow-sm ${
              m.role === 'user'
                ? 'bg-[#c49a2a] text-[#0f0f0b] rounded-tr-none font-medium'
                : 'bg-neutral-900 border border-neutral-800 text-[#e2dcd0] rounded-tl-none'
            }`}>
              <p className="whitespace-pre-wrap">{m.content}</p>
            </div>
          </div>
        ))}

        {sending && (
          <div className="flex justify-start">
            <div className="bg-neutral-950/60 border border-neutral-800 rounded-xl px-3 py-2 flex items-center gap-1.5 text-neutral-400">
              <Sparkles size={13} className="text-[#c49a2a] animate-pulse" />
              <span className="text-[11px]">Thinking</span>
              <span className="flex gap-0.5 ml-1">
                {[0, 1, 2].map((i) => (
                  <span 
                    key={i} 
                    className="w-1.5 h-1.5 bg-[#c49a2a] rounded-full animate-bounce" 
                    style={{ animationDelay: `${i * 0.15}s` }} 
                  />
                ))}
              </span>
            </div>
          </div>
        )}
      </div>

      {/* Suggested Questions Section */}
      {messages.length === 1 && !sending && (
        <div className="px-4 pb-3 space-y-2">
          <p className="text-[9px] text-[#6a6050] uppercase tracking-wider font-bold">Suggested Questions</p>
          <div className="flex flex-col gap-1">
            {Object.keys(STATIC_ANSWERS).map((q) => (
              <button
                key={q}
                onClick={() => handleSend(q)}
                className="text-[11px] text-left bg-neutral-900/50 hover:bg-neutral-900 border border-neutral-800/80 hover:border-gold-400/20 text-[#a09880] hover:text-[#f0ece0] px-3 py-2 rounded-xl transition-all"
              >
                {q}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input panel */}
      <div className="p-3 border-t border-[rgba(255,255,255,0.07)] bg-neutral-950/20">
        <div className="flex gap-2">
          <Input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask KrishiMitra..."
            disabled={sending}
            className="flex-1 bg-neutral-900 border-neutral-800 text-[#f0ece0] placeholder-neutral-600 focus-visible:ring-[#c49a2a] h-9 text-xs rounded-xl"
          />

          {browserSupportsSpeechRecognition && (
            <button
              onClick={toggleListening}
              disabled={sending}
              className={`p-2.5 rounded-xl border transition-colors flex items-center justify-center ${
                listening 
                  ? 'bg-red-950/40 border-red-800 text-red-400' 
                  : 'bg-neutral-900 border-neutral-800 text-neutral-400 hover:text-[#f0ece0]'
              }`}
            >
              {listening ? <MicOff size={14} className="animate-pulse" /> : <Mic size={14} />}
            </button>
          )}

          <button
            onClick={() => handleSend()}
            disabled={sending || !input.trim()}
            className="bg-[#c49a2a] hover:bg-[#d4aa3a] text-[#0f0f0b] font-bold rounded-xl px-3.5 h-9 text-xs flex items-center justify-center transition-colors disabled:opacity-50 disabled:hover:bg-[#c49a2a]"
          >
            <Send size={13} />
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { X, Mic, MicOff, Volume2, Sparkles, AlertCircle, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { apiGet, apiPost } from '@/lib/httpClient';

interface VoiceCommandModalProps {
  isOpen: boolean;
  onClose: () => void;
}

interface CommandGuide {
  phrase: string;
  englishPhrase: string;
  action: string;
  route: string;
}

export const VoiceCommandModal = ({ isOpen, onClose }: VoiceCommandModalProps) => {
  const navigate = useNavigate();
  const [isListening, setIsListening] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [matchedCommand, setMatchedCommand] = useState<CommandGuide | null>(null);
  const [errorMsg, setErrorMsg] = useState('');
  const [lang, setLang] = useState<'kn-IN' | 'en-US'>('kn-IN');
  const [availableCrops, setAvailableCrops] = useState<string[]>([]);
  const [userFarms, setUserFarms] = useState<string[]>([]);
  const recognitionRef = useRef<any>(null);

  // Suggested voice commands in Kannada and English
  const commandGuides: CommandGuide[] = [
    {
      phrase: 'ಬೆಳೆಗಳ ಪಟ್ಟಿ ತೋರಿಸು',
      englishPhrase: 'Show me the list of crops',
      action: 'Crops Page',
      route: '/crops',
    },
    {
      phrase: 'ಹವಾಮಾನ ವರದಿ ತೋರಿಸು',
      englishPhrase: 'Show weather report',
      action: 'Weather Details',
      route: '/weather',
    },
    {
      phrase: 'ಮಾರುಕಟ್ಟೆ ಬೆಲೆಗಳು',
      englishPhrase: 'Market prices',
      action: 'Market Prices',
      route: '/market-prices',
    },
    {
      phrase: 'ನನ್ನ ಜಮೀನು',
      englishPhrase: 'My farm details',
      action: 'My Farm Page',
      route: '/my-farm',
    },
    {
      phrase: 'ಸರ್ಕಾರಿ ಯೋಜನೆಗಳು',
      englishPhrase: 'Government schemes',
      action: 'Gov Schemes',
      route: '/schemes',
    },
    {
      phrase: 'ಮಣ್ಣಿನ ಪರೀಕ್ಷೆ ಮಾಡು',
      englishPhrase: 'Soil analysis',
      action: 'Soil analysis',
      route: '/soil-analysis',
    },
    {
      phrase: 'ರೈತರ ಸಮುದಾಯ',
      englishPhrase: 'Farmers community',
      action: 'Community forum',
      route: '/community',
    },
    {
      phrase: 'ಮುಖಪುಟಕ್ಕೆ ಹೋಗು',
      englishPhrase: 'Go to dashboard',
      action: 'Dashboard',
      route: '/dashboard',
    },
    {
      phrase: 'ಕೃಷಿ ಮಿತ್ರ ಸಹಾಯ',
      englishPhrase: 'Krishi Mitra AI Assistant',
      action: 'Open AI Assistant',
      route: 'krishimitra',
    },
  ];

  // Text to Speech in Kannada
  const speakFeedback = (text: string) => {
    if ('speechSynthesis' in window) {
      // Cancel any current speaking
      window.speechSynthesis.cancel();

      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = lang;

      // Try to find a matching voice locale
      const voices = window.speechSynthesis.getVoices();
      const matchedVoice = voices.find(voice => voice.lang.startsWith(lang.split('-')[0]));
      if (matchedVoice) {
        utterance.voice = matchedVoice;
      }

      utterance.rate = 0.95; // Slightly slower for better clarity
      window.speechSynthesis.speak(utterance);
    }
  };

  // Local fallback keyword matcher
  const runLocalFallback = (spokenText: string): CommandGuide | null => {
    const textLower = spokenText.toLowerCase().trim();

    const KANNADA_CROP_MAP: Record<string, string> = {
      'ರಾಗಿ': 'ragi',
      'ಭತ್ತ': 'rice',
      'ಅಕ್ಕಿ': 'rice',
      'ಗೋಧಿ': 'wheat',
      'ಮೆಕ್ಕೆಜೋಳ': 'maize',
      'ಜೋಳ': 'jowar',
      'ಕಬ್ಬು': 'sugarcane',
      'ಹತ್ತಿ': 'cotton',
      'ಶೇಂಗಾ': 'groundnut',
      'ಕಡಲೆಕಾಯಿ': 'groundnut',
      'ಬೆಳ್ಳುಳ್ಳಿ': 'garlic',
      'ಈರುಳ್ಳಿ': 'onion',
      'ಶುಂಠಿ': 'ginger',
      'ಕಾಫಿ': 'coffee',
      'ಟೊಮೆಟೊ': 'tomato',
      'ಆಲೂಗಡ್ಡೆ': 'potato',
      'ಬದನೆಕಾಯಿ': 'brinjal',
      'ಮೆಣಸಿನಕಾಯಿ': 'chilli',
      'ತೆಂಗಿನಕಾಯಿ': 'coconut'
    };

    // 1. Check for specific crop matches in Kannada crop map
    for (const [knName, enName] of Object.entries(KANNADA_CROP_MAP)) {
      if (textLower.includes(knName)) {
        const matchedCrop = availableCrops.find(c => c.toLowerCase().includes(enName));
        if (matchedCrop) {
          const slug = matchedCrop.toLowerCase().trim()
            .replace(/[^\w\s-]/g, '')
            .replace(/[\s/]+/g, '-')
            .replace(/-+/g, '-')
            .replace(/^-+|-+$/g, '');
          return {
            phrase: `${matchedCrop} ಬೆಳೆ ವಿವರ`,
            englishPhrase: `${matchedCrop} Crop Details`,
            action: `${matchedCrop} Details`,
            route: `/crop/${slug}`
          };
        }
      }
    }

    // 2. Check for specific crop matches in English availableCrops
    for (const crop of availableCrops) {
      const cropLower = crop.toLowerCase();
      // Split Ragi (Finger Millet) into ["ragi", "finger millet"]
      const parts = cropLower.split(/[()]/).map(p => p.trim()).filter(Boolean);
      for (const part of parts) {
        if (part.length > 2 && textLower.includes(part)) {
          const slug = crop.toLowerCase().trim()
            .replace(/[^\w\s-]/g, '')
            .replace(/[\s/]+/g, '-')
            .replace(/-+/g, '-')
            .replace(/^-+|-+$/g, '');
          return {
            phrase: `${crop} ಬೆಳೆ ವಿವರ`,
            englishPhrase: `${crop} Crop Details`,
            action: `${crop} Details`,
            route: `/crop/${slug}`
          };
        }
      }
    }

    // 3. Generic matches (e.g. general crops registry, weather, farm, etc.)
    if (
      textLower.includes('ಬೆಳೆ') || 
      textLower.includes('ಬೆಳೆಗಳು') || 
      textLower.includes('ಬೆಳೆಗಳ') ||
      textLower.includes('crop') ||
      textLower.includes('crops')
    ) {
      return commandGuides[0]; // Crops Page
    }
    if (
      textLower.includes('ಹವಾಮಾನ') || 
      textLower.includes('ಹವೆ') || 
      textLower.includes('ಮಳೆ') ||
      textLower.includes('weather') ||
      textLower.includes('rain') ||
      textLower.includes('forecast')
    ) {
      return commandGuides[1]; // Weather
    }
    if (
      textLower.includes('ಮಾರುಕಟ್ಟೆ') || 
      textLower.includes('ಬೆಲೆ') || 
      textLower.includes('ಧಾರಣೆ') ||
      textLower.includes('ದರ') ||
      textLower.includes('ರೇಟ್') ||
      textLower.includes('market') ||
      textLower.includes('price') ||
      textLower.includes('prices')
    ) {
      return commandGuides[2]; // Market Prices
    }
    if (
      textLower.includes('ಜಮೀನು') || 
      textLower.includes('ಹೊಲ') || 
      textLower.includes('ತೋಟ') ||
      textLower.includes('ಫಾರ್ಮ್') ||
      textLower.includes('farm') ||
      textLower.includes('land')
    ) {
      return commandGuides[3]; // My Farm
    }
    if (
      textLower.includes('ಯೋಜನೆ') || 
      textLower.includes('ಯೋಜನೆಗಳು') || 
      textLower.includes('ಸರ್ಕಾರ') ||
      textLower.includes('scheme') ||
      textLower.includes('schemes') ||
      textLower.includes('yojana')
    ) {
      return commandGuides[4]; // Gov Schemes
    }
    if (
      textLower.includes('ಮಣ್ಣು') || 
      textLower.includes('ಮಣ್ಣಿನ') || 
      textLower.includes('ಪರೀಕ್ಷೆ') ||
      textLower.includes('soil')
    ) {
      return commandGuides[5]; // Soil Analysis
    }
    if (
      textLower.includes('ಸಮುದಾಯ') || 
      textLower.includes('ಚರ್ಚೆ') || 
      textLower.includes('ಗೆಳೆಯರು') ||
      textLower.includes('ರೈತರು') ||
      textLower.includes('community') ||
      textLower.includes('forum')
    ) {
      return commandGuides[6]; // Community
    }
    if (
      textLower.includes('ಮುಖಪುಟ') || 
      textLower.includes('ಡ್ಯಾಶ್') || 
      textLower.includes('ಮುಖ್ಯ') ||
      textLower.includes('dashboard') ||
      textLower.includes('home')
    ) {
      return commandGuides[7]; // Dashboard
    }
    if (
      textLower.includes('ಮಿತ್ರ') || 
      textLower.includes('ಕೃಷಿಮಿತ್ರ') || 
      textLower.includes('ಕೃಷಿ ಮಿತ್ರ') || 
      textLower.includes('ಸಹಾಯ') ||
      textLower.includes('assistant') ||
      textLower.includes('krishi') ||
      textLower.includes('help')
    ) {
      return commandGuides[8]; // Krishi Mitra
    }
    if (
      textLower.includes('ಪ್ರೊಫೈಲ್') || 
      textLower.includes('ಖಾತೆ') || 
      textLower.includes('profile')
    ) {
      return {
        phrase: 'ಪ್ರೊಫೈಲ್',
        englishPhrase: 'Profile page',
        action: 'Profile Settings',
        route: '/profile'
      };
    }
    return null;
  };

  const cleanMarkdown = (text: string): string => {
    if (!text) return '';
    let cleaned = text.trim();
    if (cleaned.startsWith('```')) {
      cleaned = cleaned.replace(/^```[a-zA-Z]*\s*/, '').replace(/\s*```$/, '').trim();
    }
    return cleaned;
  };

  // Process and match the spoken transcript
  const processTranscript = async (spokenText: string) => {
    setIsListening(false);
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }

    setIsAnalyzing(true);
    let matched: CommandGuide | null = null;

    // Dynamically build system prompt with crop names and farm names from DB
    const dynamicSystemPrompt = `You are the voice command intent classifier for Agri Compass.
Analyze the user's spoken input (in Kannada or English) and classify it into one of these intents and target paths:
- Intent: 'CROPS', Path: '/crops'
- Intent: 'WEATHER', Path: '/weather'
- Intent: 'MARKET_PRICES', Path: '/market-prices'
- Intent: 'MY_FARM', Path: '/my-farm'
- Intent: 'GOV_SCHEMES', Path: '/schemes'
- Intent: 'SOIL_ANALYSIS', Path: '/soil-analysis'
- Intent: 'COMMUNITY', Path: '/community'
- Intent: 'DASHBOARD', Path: '/dashboard'
- Intent: 'PROFILE', Path: '/profile'
- Intent: 'ASSISTANT', Path: 'krishimitra'
- Intent: 'UNKNOWN', Path: ''

DATABASE CONTEXT:
- Available Crops: [ ${availableCrops.join(', ')} ]
- User's Farms: [ ${userFarms.join(', ')} ]

ADDITIONAL ROUTING RULES:
1. If the user mentions any crop in the "Available Crops" list (like "Rice" or "ರಾಗಿ"), set the Path to "/crop/CropName" where CropName is the matched crop name in English (Capitalized, e.g. "Rice", "Maize", "Ragi").
2. If they ask about a specific farm in the "User's Farms" list, route to "/my-farm".

Respond ONLY with a minified, valid JSON object matching this schema:
{"intent": "INTENT_NAME", "path": "TARGET_PATH", "reason": "Brief explanation in English"}
Do NOT wrap the response in markdown code blocks like \`\`\`. Output plain text JSON only.`;

    try {
      // 1. Send the speech transcript to Gemini classifier backend endpoint
      const response = await apiPost('/api/ai/chat', {
        prompt: spokenText,
        systemContext: dynamicSystemPrompt
      });

      if (response && response.success && response.response) {
        const cleanedJson = cleanMarkdown(response.response);
        try {
          const result = JSON.parse(cleanedJson);
          if (result && result.path) {
            // Find in commandGuides or create a dynamic one
            const targetPath = result.path;
            const existingGuide = commandGuides.find(g => g.route === targetPath);
            if (existingGuide) {
              matched = existingGuide;
            } else if (targetPath === '/profile') {
              matched = {
                phrase: 'ಪ್ರೊಫೈಲ್',
                englishPhrase: 'Profile page',
                action: 'Profile Settings',
                route: '/profile'
              };
            } else if (targetPath.startsWith('/crop/')) {
              let cropParam = targetPath.split('/').pop() || '';
              cropParam = decodeURIComponent(cropParam).toLowerCase().trim();

              // Find the matching crop dynamically from availableCrops list
              const matchedCrop = availableCrops.find(c => {
                const name = c.toLowerCase().trim();
                const slugName = c.toLowerCase().trim()
                  .replace(/[^\w\s-]/g, '')
                  .replace(/[\s/]+/g, '-')
                  .replace(/-+/g, '-')
                  .replace(/^-+|-+$/g, '');

                return name === cropParam || 
                       slugName === cropParam || 
                       name.includes(cropParam) || 
                       cropParam.includes(name);
              });

              const targetCrop = matchedCrop || cropParam;
              const slug = targetCrop.toLowerCase().trim()
                .replace(/[^\w\s-]/g, '')
                .replace(/[\s/]+/g, '-')
                .replace(/-+/g, '-')
                .replace(/^-+|-+$/g, '');

              matched = {
                phrase: `${targetCrop} ಬೆಳೆ ವಿವರ`,
                englishPhrase: `${targetCrop} Crop Details`,
                action: `${targetCrop} Details`,
                route: `/crop/${slug}`
              };
            }
          }
        } catch (jsonErr) {
          console.warn('Failed to parse classifier JSON response, using fallback', jsonErr);
        }
      }
    } catch (apiErr) {
      console.warn('Classifier API call failed, using local fallback matching', apiErr);
    }

    // 2. Local fallback if AI classification failed or returned UNKNOWN
    if (!matched) {
      matched = runLocalFallback(spokenText);
    }

    setIsAnalyzing(false);

    if (matched) {
      setMatchedCommand(matched);

      // Audio confirmation in Kannada or English
      const feedbackText = lang === 'kn-IN'
        ? `${matched.phrase} ಪುಟಕ್ಕೆ ಹೋಗಲಾಗುತ್ತಿದೆ`
        : `Navigating to ${matched.action}`;

      speakFeedback(feedbackText);

      // Execute navigation after short delay to let user see match
      setTimeout(() => {
        onClose();
        if (matched?.route === 'krishimitra') {
          // Trigger the KrishiMitra float assistant event
          window.dispatchEvent(new CustomEvent('open-krishimitra'));
        } else if (matched?.route) {
          navigate(matched.route);
        }
        // Reset states
        setTranscript('');
        setMatchedCommand(null);
      }, 1500);
    } else {
      // Speak out warning if no match found
      const retryText = lang === 'kn-IN'
        ? "ಕ್ಷಮಿಸಿ, ಆಜ್ಞೆ ಅರ್ಥವಾಗಲಿಲ್ಲ. ದಯವಿಟ್ಟು ಮತ್ತೊಮ್ಮೆ ಪ್ರಯತ್ನಿಸಿ."
        : "Sorry, command not recognized. Please try again.";
      speakFeedback(retryText);
    }
  };

  // Start Speech Recognition
  const startSpeech = () => {
    setErrorMsg('');
    setTranscript('');
    setMatchedCommand(null);

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setErrorMsg('ನಿಮ್ಮ ಬ್ರೌಸರ್ ಧ್ವನಿ ಗುರುತಿಸುವಿಕೆಯನ್ನು ಬೆಂಬಲಿಸುವುದಿಲ್ಲ. / Your browser does not support Speech Recognition.');
      return;
    }

    try {
      const recognition = new SpeechRecognition();
      recognition.continuous = false;
      recognition.interimResults = true;
      recognition.lang = lang;

      recognition.onstart = () => {
        setIsListening(true);
      };

      recognition.onresult = (event: any) => {
        const current = event.resultIndex;
        const resultTranscript = event.results[current][0].transcript;
        setTranscript(resultTranscript);

        if (event.results[current].isFinal) {
          processTranscript(resultTranscript);
        }
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event);
        setIsListening(false);
        if (event.error === 'not-allowed') {
          setErrorMsg('ಮೈಕ್ರೊಫೋನ್ ಅನುಮತಿಯನ್ನು ನಿರಾಕರಿಸಲಾಗಿದೆ. ದಯವಿಟ್ಟು ಬ್ರೌಸರ್ ಸೆಟ್ಟಿಂಗ್ಸ್ ಪರಿಶೀಲಿಸಿ. / Microphone access denied. Please check your browser permissions.');
        } else if (event.error === 'network') {
          setErrorMsg('Network Error: If you are using Brave Browser, please disable Brave Shields for this site, or use Chrome/Edge.');
        } else {
          setErrorMsg(`ದೋಷ ಸಂಭವಿಸಿದೆ: ${event.error} / Error: ${event.error}`);
        }
      };

      recognition.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current = recognition;
      recognition.start();
    } catch (err: any) {
      setErrorMsg(`ದೋಷ: ${err.message || err}`);
      setIsListening(false);
    }
  };

  // Handle clicking a template card to test the navigation
  const triggerSampleCommand = (guide: CommandGuide) => {
    setTranscript(lang === 'kn-IN' ? guide.phrase : guide.englishPhrase);
    setMatchedCommand(guide);

    const feedbackText = lang === 'kn-IN'
      ? `${guide.phrase} ಪುಟಕ್ಕೆ ಹೋಗಲಾಗುತ್ತಿದೆ`
      : `Navigating to ${guide.action}`;
    speakFeedback(feedbackText);

    setTimeout(() => {
      onClose();
      if (guide.route === 'krishimitra') {
        window.dispatchEvent(new CustomEvent('open-krishimitra'));
      } else {
        navigate(guide.route);
      }
      setTranscript('');
      setMatchedCommand(null);
    }, 1500);
  };

  useEffect(() => {
    const fetchContextData = async () => {
      try {
        const cropsRes = await apiGet('/api/crops?size=50');
        if (cropsRes && cropsRes.content) {
          const names = cropsRes.content.map((c: any) => c.name).filter(Boolean);
          setAvailableCrops(names);
        }
      } catch (err) {
        console.warn('Failed to fetch crops context:', err);
      }

      try {
        const farmsRes = await apiGet('/api/farms');
        if (Array.isArray(farmsRes)) {
          const names = farmsRes.map((f: any) => f.name).filter(Boolean);
          setUserFarms(names);
        }
      } catch (err) {
        console.warn('Failed to fetch farms context:', err);
      }
    };

    if (isOpen) {
      fetchContextData();
      setTimeout(() => {
        startSpeech();
      }, 300);
    } else {
      // Clean up on close
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      setIsListening(false);
      setTranscript('');
      setMatchedCommand(null);
      setErrorMsg('');
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, [isOpen, lang]);

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-neutral-950/80 backdrop-blur-md">
          {/* Modal Backdrop Container */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="w-full max-w-2xl bg-[#1a1a14] border border-[rgba(196,154,42,0.25)] rounded-2xl shadow-premium overflow-hidden"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-[rgba(255,255,255,0.07)] bg-neutral-950/20">
              <div className="flex items-center gap-2.5">
                <div className="w-8 h-8 rounded-full bg-[rgba(196,154,42,0.15)] flex items-center justify-center">
                  <Sparkles size={16} className="text-[#c49a2a]" />
                </div>
                <div>
                  <h3 className="text-sm font-black tracking-widest text-[#f0ece0] uppercase">
                    {lang === 'kn-IN' ? 'ಧ್ವನಿ ಆಜ್ಞೆಗಳು' : 'Voice Navigation'}
                  </h3>
                  <p className="text-[10px] text-[#6a6050] uppercase font-bold tracking-wider">
                    {lang === 'kn-IN' ? 'ಮಾತನಾಡಿ ನ್ಯಾವಿಗೇಟ್ ಮಾಡಿ' : 'Speak to navigate'}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                {/* Language Switcher inside voice search */}
                <div className="flex bg-neutral-950/50 border border-earth-border/40 rounded-full p-0.5">
                  <button
                    onClick={() => setLang('kn-IN')}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${
                      lang === 'kn-IN'
                        ? 'bg-[#c49a2a] text-[#0f0f0b]'
                        : 'text-gold-100/50 hover:text-gold-100'
                    }`}
                  >
                    ಕನ್ನಡ
                  </button>
                  <button
                    onClick={() => setLang('en-US')}
                    className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${
                      lang === 'en-US'
                        ? 'bg-[#c49a2a] text-[#0f0f0b]'
                        : 'text-gold-100/50 hover:text-gold-100'
                    }`}
                  >
                    English
                  </button>
                </div>
                <button
                  onClick={onClose}
                  className="w-8 h-8 rounded-full hover:bg-white/5 flex items-center justify-center transition-colors"
                >
                  <X size={18} className="text-[#a09880]" />
                </button>
              </div>
            </div>

            {/* Listening Area */}
            <div className="px-6 py-10 flex flex-col items-center justify-center text-center bg-radial-gradient">
              {/* Pulsing microphone / wave representation */}
              <div className="relative mb-6">
                <AnimatePresence>
                  {isListening && (
                    <>
                      {/* Pulse rings */}
                      <motion.span
                        initial={{ opacity: 0.4, scale: 0.8 }}
                        animate={{ opacity: 0, scale: 2 }}
                        exit={{ opacity: 0 }}
                        transition={{ repeat: Infinity, duration: 1.5, ease: 'easeOut' }}
                        className="absolute inset-0 rounded-full bg-[#c49a2a]"
                      />
                      <motion.span
                        initial={{ opacity: 0.3, scale: 0.8 }}
                        animate={{ opacity: 0, scale: 1.6 }}
                        exit={{ opacity: 0 }}
                        transition={{ repeat: Infinity, duration: 1.5, delay: 0.5, ease: 'easeOut' }}
                        className="absolute inset-0 rounded-full bg-[#c49a2a]"
                      />
                    </>
                  )}
                </AnimatePresence>
                <button
                  onClick={isListening ? () => {
                    setIsListening(false);
                    if (recognitionRef.current) recognitionRef.current.stop();
                  } : startSpeech}
                  className={`relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 ${
                    isListening
