export const MarketTrendRow = React.memo(({ crop, index }: { crop: MarketTrend; index: number }) => {
  const hasData = crop.changePercent !== null && crop.price !== null;
  const isUp   = hasData && crop.changePercent! > 0
  const isDown = hasData && crop.changePercent! < 0
  const isFlat = hasData && crop.changePercent === 0

  return (
    <motion.div
      initial={{ opacity: 0, height: 0 }}
      animate={{ opacity: 1, height: 'auto' }}
      exit={{ opacity: 0, height: 0 }}
      transition={{ type: "spring", stiffness: 300, damping: 24 }}
      className="flex items-center justify-between py-2.5 px-3 rounded-xl hover:bg-white/5 hover:scale-[1.02] border border-transparent hover:border-gold-400/20 transition-all cursor-pointer group shadow-sm hover:shadow-md overflow-hidden"
      onClick={() => window.location.href = `/market-prices?crop=${crop.name}`}
    >
      {/* Crop name + season */}
      <div className="flex items-center gap-3 flex-1 min-w-0">
        <div className="w-8 h-8 rounded-lg overflow-hidden flex-shrink-0 bg-earth-border/20 border border-earth-border/40 group-hover:border-gold-400/30 transition-colors shadow-inner">
          <img
            src={getCropImage(crop.name)}
            alt={crop.name}
            className="w-full h-full object-cover opacity-90 group-hover:opacity-100 transition-opacity"
            onError={e => e.currentTarget.style.display = 'none'}
          />
        </div>
        <div className="min-w-0">
          <p className="text-xs font-bold text-gold-100 truncate tracking-wide group-hover:text-white transition-colors">{crop.name}</p>
          <p className="text-[10px] text-gold-100/70 uppercase font-black tracking-widest">{crop.unit}</p>
        </div>
      </div>

      {/* Sparkline mini chart — CSS animated bars */}
      <div className="flex items-end gap-[3px] h-6 mx-4 w-12">
        {crop.sparkline ? crop.sparkline.map((val, i) => {
          const max = Math.max(...crop.sparkline!)
          const height = Math.max(4, Math.round((val / max) * 22))
          const isLast = i === crop.sparkline!.length - 1
          return (
            <div
              key={i}
              className={`w-1 rounded-sm transition-all duration-300 ${
                isLast
                  ? isUp   ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]'
                    : isDown ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'
                    : 'bg-gold-400 shadow-[0_0_8px_rgba(196,154,42,0.6)]'
                  : 'bg-earth-border/60 group-hover:bg-earth-border/80'
              }`}
              style={{ height: `${height}px` }}
            />
          )
        }) : (
          <div className="w-full h-0.5 bg-earth-border/40 mb-1" />
        )}
      </div>

      {/* Price + change */}
      <div className="text-right flex-shrink-0">
        <p className={`text-[13px] font-black tracking-tight ${hasData ? 'text-gold-100' : 'text-gold-100/70'}`}>
          {hasData ? `₹${formatIndianNumber(crop.price!)}` : 'N/A'}
        </p>
        <div className={`flex items-center justify-end gap-1 text-[10px] font-black uppercase tracking-widest mt-0.5 ${
          !hasData ? 'text-gold-100/70'
          : isUp   ? 'text-green-400'
          : isDown ? 'text-red-400'
          : 'text-gold-100/50'
        }`}>
          {hasData ? (
            <>
              {isUp   && <TrendingUp size={10} className="stroke-[3]" />}
              {isDown && <TrendingDown size={10} className="stroke-[3]" />}
              {isFlat && <Minus size={10} className="stroke-[3]" />}
              {isFlat ? 'Stable' : `${isUp ? '+' : ''}${crop.changePercent!.toFixed(1)}%`}
            </>
          ) : (
            '--'
          )}
        </div>
      </div>
    </motion.div>
  )
})

