                    <p className="text-[12px] font-bold text-[#f0ece0] truncate">{listing.sellerName || 'Farmer Partner'}</p>
                    {listing.sellerVerified && (
                      <p className="text-[10px] text-[#4a9a6a] font-bold flex items-center gap-1">
