import { useState, useEffect, useRef, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useAuth, useUser } from "@clerk/clerk-react";
import { Client } from "@stomp/stompjs";
import SockJS from "sockjs-client";
import { motion } from "framer-motion";
import { buildUrl } from "../lib/httpClient";

interface Message {
  id: string;
  conversationId: string;
  senderId: string;
  content: string;
  createdAt: string;
  pending?: boolean;
}

export const ChatPage = () => {
  const { userId: otherUserId } = useParams<{ userId: string }>();
  const { getToken } = useAuth();
  const { user } = useUser();
  const navigate = useNavigate();

  const [otherUser, setOtherUser] = useState<any>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [conversationId, setConversationId] = useState<string | null>(null);
  const [input, setInput] = useState("");
  const [connected, setConnected] = useState(false);
  const [loading, setLoading] = useState(true);

  const stompRef = useRef<Client | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  const scrollToBottom = useCallback(() => {
    setTimeout(() => messagesEndRef.current?.scrollIntoView({ behavior: "smooth" }), 50);
  }, []);

  // Setup conversation and load history
  useEffect(() => {
    if (!otherUserId || !user?.id) return;
    let isMounted = true;

    const setup = async () => {
      setLoading(true);
      const token = await getToken();
      const base = import.meta.env.VITE_API_BASE_URL ?? "";
      try {
        // Get other user's profile
        const profileData = await fetch(`${base}/api/users/${otherUserId}/public`).then(r => r.json());
        if (isMounted) setOtherUser(profileData.profile ?? profileData);

        // Get or create conversation
        const convData = await fetch(`${base}/api/conversations/user/${otherUserId}`, {
          headers: { Authorization: `Bearer ${token}` },
        }).then(r => r.json());
        const convId = convData.conversationId ?? convData.id;
        if (isMounted) setConversationId(convId);

        // Load messages
        const msgData = await fetch(`${base}/api/messages/${convId}`, {
          headers: { Authorization: `Bearer ${token}` },
        }).then(r => r.json());
        if (isMounted) setMessages(msgData.messages ?? msgData ?? []);

        // Mark as read
        fetch(`${base}/api/messages/${convId}/read`, {
          method: "POST",
          headers: { Authorization: `Bearer ${token}` },
        }).catch(() => {});
      } catch (err) {
        console.error("Chat setup failed:", err);
      } finally {
        if (isMounted) {
          setLoading(false);
          scrollToBottom();
        }
      }
    };
    setup();
    return () => { isMounted = false; };
  }, [otherUserId, user?.id]);

  // WebSocket — uses env variable, not hardcoded localhost
  useEffect(() => {
    if (!conversationId || !user?.id) return;

    const client = new Client({
      webSocketFactory: () => new SockJS(buildUrl('/ws')),
      onConnect: () => {
        setConnected(true);
        client.subscribe(`/topic/messages.${user.id}`, frame => {
          const msg: Message = JSON.parse(frame.body);
          if (msg.conversationId === conversationId) {
            setMessages(prev => {
              const exists = prev.some(m => m.id === msg.id);
              return exists ? prev : [...prev, msg];
            });
            scrollToBottom();
          }
        });
      },
      onDisconnect: () => setConnected(false),
      reconnectDelay: 3000,
    });

    client.activate();
    stompRef.current = client;
    return () => { client.deactivate(); };
  }, [conversationId, user?.id]);

  const sendMessage = useCallback(() => {
    if (!input.trim() || !conversationId) return;
    const content = input.trim();
    setInput("");

    // Optimistic UI update
    const tempMsg: Message = {
      id: `temp-${Date.now()}`,
      conversationId,
      senderId: user!.id,
      content,
      createdAt: new Date().toISOString(),
      pending: true,
    };
    setMessages(prev => [...prev, tempMsg]);
    scrollToBottom();

    // Send via STOMP if connected, otherwise via REST
    if (stompRef.current?.connected) {
      stompRef.current.publish({
        destination: "/app/chat.send",
        body: JSON.stringify({ conversationId, recipientId: otherUserId, content }),
      });
    } else {
      const base = import.meta.env.VITE_API_BASE_URL ?? "";
      getToken().then(token => {
        fetch(`${base}/api/messages/${conversationId}`, {
          method: "POST",
          headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
          body: JSON.stringify({ content, recipientId: otherUserId }),
        }).catch(console.error);
      });
    }

    if (inputRef.current) inputRef.current.style.height = "auto";
  }, [input, conversationId, otherUserId, user]);

  // Group messages by date label
  const groupByDate = (msgs: Message[]) => {
    const groups: Record<string, Message[]> = {};
    msgs.forEach(msg => {
      const d = new Date(msg.createdAt);
      const today = new Date();
      const yesterday = new Date(today);
      yesterday.setDate(yesterday.getDate() - 1);
      let label: string;
      if (d.toDateString() === today.toDateString()) label = "Today";
      else if (d.toDateString() === yesterday.toDateString()) label = "Yesterday";
      else label = d.toLocaleDateString("en-IN", { day: "numeric", month: "long" });
      if (!groups[label]) groups[label] = [];
      groups[label].push(msg);
    });
    return groups;
  };

  const formatTime = (iso: string) =>
    new Date(iso).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" });

  return (
    <div className="h-screen bg-[#0A0A0A] flex flex-col">
      <div className="glass-panel sticky top-0 z-10 px-5 py-3 border-b border-[#1E1E1E] flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate("/messages")} className="text-[#F5F0E8]/40 hover:text-[#C9A84C] transition-colors p-1">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          </button>

          {loading ? (
            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-full bg-[#1E1E1E] animate-pulse" />
              <div className="space-y-1.5">
                <div className="h-3 bg-[#1E1E1E] rounded w-24 animate-pulse" />
                <div className="h-2 bg-[#1E1E1E] rounded w-16 animate-pulse" />
              </div>
            </div>
          ) : (
            <div className="flex items-center gap-3 flex-1">
              <div className="relative">
                <div className="w-9 h-9 rounded-full overflow-hidden bg-[#C9A84C]/10 flex items-center justify-center flex-shrink-0">
                  {otherUser?.profilePictureUrl || otherUser?.profile_picture_url
                    ? <img src={otherUser.profilePictureUrl || otherUser.profile_picture_url} className="w-full h-full object-cover" alt="" />
                    : <span className="text-[#C9A84C] text-sm font-semibold">{(otherUser?.fullName || otherUser?.full_name || "?")[0]}</span>
                  }
                </div>
                {connected && (
                  <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-400 rounded-full border-2 border-[#0A0A0A]" />
                )}
              </div>
              <div>
                <p className="text-[#F5F0E8] text-sm font-semibold">{otherUser?.fullName || otherUser?.full_name}</p>
                <p className="text-[#F5F0E8]/30 text-xs">@{otherUser?.usernameHandle || otherUser?.username_handle} · {otherUser?.district}</p>
              </div>
            </div>
          )}
        </div>

        <div className="flex items-center gap-1.5 flex-shrink-0 bg-[#111] px-2 py-1 rounded-full border border-[#1E1E1E]">
          <div className={`w-1.5 h-1.5 rounded-full transition-colors ${connected ? "bg-green-400" : "bg-[#C9A84C] animate-pulse"}`} />
          <span className="text-[#F5F0E8]/30 text-[10px] uppercase font-bold tracking-wider">{connected ? "Live" : "Connecting..."}</span>
        </div>
      </div>

      {/* Messages area */}
      <div className="flex-1 overflow-y-auto px-4 py-6">
        {loading ? (
          <div className="flex items-center justify-center h-full">
            <div className="text-[#C9A84C] animate-pulse text-2xl">💬</div>
          </div>
        ) : messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center px-6">
            <div className="w-16 h-16 rounded-full bg-[#C9A84C]/10 border border-[#C9A84C]/20 flex items-center justify-center mb-4">
              {otherUser?.profilePictureUrl || otherUser?.profile_picture_url
                ? <img src={otherUser.profilePictureUrl || otherUser.profile_picture_url} className="w-full h-full rounded-full object-cover" alt="" />
                : <span className="text-[#C9A84C] text-xl font-semibold">{(otherUser?.fullName || otherUser?.full_name || "?")[0]}</span>
              }
            </div>
            <p className="text-[#F5F0E8]/60 font-medium mb-1">{otherUser?.fullName || otherUser?.full_name}</p>
            <p className="text-[#F5F0E8]/25 text-sm">Send a message to start the conversation</p>
          </div>
        ) : (
          Object.entries(groupByDate(messages)).map(([date, msgs]) => (
            <div key={date}>
              {/* Date separator */}
              <div className="flex items-center gap-3 my-6">
                <div className="flex-1 h-px bg-[#1E1E1E]" />
                <span className="text-[#F5F0E8]/15 text-xs px-2">{date}</span>
                <div className="flex-1 h-px bg-[#1E1E1E]" />
              </div>

              <div className="space-y-1.5">
                {(msgs as Message[]).map((msg, i) => {
                  const isMe = msg.senderId === user?.id;
                  const nextMsg = (msgs as Message[])[i + 1];
                  const isLastInGroup = !nextMsg || nextMsg.senderId !== msg.senderId;

                  return (
                    <motion.div key={msg.id}
                      initial={{ opacity: 0, y: 6 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ duration: 0.2 }}
                      className={`flex items-end gap-2 ${isMe ? "justify-end" : "justify-start"}`}>

                      {/* Other user avatar — only on last msg in group */}
                      {!isMe && (
                        <div className="w-7 flex-shrink-0 mb-1">
                          {isLastInGroup && (
                            <div className="w-7 h-7 rounded-full overflow-hidden bg-[#C9A84C]/10 flex items-center justify-center">
                              {otherUser?.profilePictureUrl || otherUser?.profile_picture_url
                                ? <img src={otherUser.profilePictureUrl || otherUser.profile_picture_url} className="w-full h-full object-cover" alt="" />
                                : <span className="text-[#C9A84C] text-xs font-semibold">{(otherUser?.fullName || otherUser?.full_name || "?")[0]}</span>
                              }
                            </div>
                          )}
                        </div>
                      )}

                      <div className={`max-w-[70%] flex flex-col ${isMe ? "items-end" : "items-start"}`}>
                        <div className={`px-4 py-2.5 text-sm leading-relaxed shadow-sm ${
                          isMe
                            ? "bg-[#C9A84C] text-[#0A0A0A] font-medium rounded-2xl rounded-br-sm shadow-[0_2px_10px_rgba(201,168,76,0.15)]"
                            : "glass-panel text-[#F5F0E8] rounded-2xl rounded-bl-sm"
                        } ${msg.pending ? "opacity-60" : ""}`}>
                          {msg.content}
                        </div>
                        {isLastInGroup && (
                          <p className="text-[#F5F0E8]/15 text-xs mt-1 px-1">
                            {formatTime(msg.createdAt)}{isMe && !msg.pending ? " ✓" : ""}
                          </p>
                        )}
                      </div>
                    </motion.div>
                  );
                })}
              </div>
            </div>
          ))
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input bar */}
      <div className="glass-panel flex-shrink-0 px-4 py-3 sticky bottom-0">
        <div className="flex items-end gap-3 bg-[#111]/80 backdrop-blur-md border border-[#1E1E1E] rounded-2xl px-4 py-3 focus-within:border-[#C9A84C]/40 focus-within:ring-2 focus-within:ring-[#C9A84C]/10 transition-all shadow-inner">
          <textarea
            ref={inputRef}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                sendMessage();
              }
            }}
            placeholder="Type your message..."
            rows={1}
            className="flex-1 bg-transparent text-[#F5F0E8] text-sm placeholder:text-[#F5F0E8]/20 focus:outline-none resize-none max-h-28 overflow-y-auto"
            onInput={e => {
              const t = e.target as HTMLTextAreaElement;
              t.style.height = "auto";
              t.style.height = `${Math.min(t.scrollHeight, 112)}px`;
            }}
          />
          <button onClick={sendMessage}
            disabled={!input.trim()}
            aria-label="Send message"
            className="w-8 h-8 bg-[#C9A84C] rounded-xl flex items-center justify-center flex-shrink-0 disabled:opacity-20 hover:bg-[#D4B86A] hover:-translate-y-0.5 hover:shadow-[0_0_15px_rgba(201,168,76,0.4)] transition-all">
            <span className="text-[#0A0A0A] font-bold text-base leading-none mb-0.5">↑</span>
          </button>
        </div>
        {!connected && (
          <p className="text-center text-xs text-[#F5F0E8]/20 mt-2">Reconnecting to live chat...</p>
        )}
      </div>
    </div>
  );
};

export default ChatPage;

import { useState, useEffect, useMemo } from 'react'
import { useNavigate } from 'react-router-dom';
import { useUser } from '@clerk/clerk-react';
import { useDistrict } from '@/store';
import { PostsAPI, Post } from '@/lib/api/posts'
import { UploadAPI } from '@/lib/api/upload'
import { useCommunityFeed } from '@/hooks/useCommunityFeed'
import { Button } from '@/components/ui/button'
import { Card } from '@/components/ui/card'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { PostCard } from '@/components/ui/post-card'
import { useToast } from '@/hooks/use-toast'
import { ScrollReveal, StaggerContainer, StaggerItem } from '@/components/ui/animations'
import { LottieEmptyState } from '@/components/ui/lottie-loading'
import { PostListSkeleton } from '@/components/ui/post-skeleton'
import { Plus, ImagePlus, Video, Search, Calendar, MapPin, X, Activity, Filter, MessageSquare, ShoppingCart } from 'lucide-react'
import { useDropzone } from 'react-dropzone'
import { Badge } from '@/components/ui/badge'
import { EmptyState } from '@/components/ui/EmptyState'
import { cn } from '@/lib/utils'
import { Marketplace } from '@/features/community/components/Marketplace'

const TOPICS = [
  { id: 'all', label: 'All Feed', keywords: [] },
  { id: 'crops', label: 'Crops & Seeds', keywords: ['crop', 'seed', 'paddy', 'rice', 'ragi', 'sugarcane', 'cotton', 'bel', 'bennu', 'ಬೆಳೆ', 'ಭತ್ತ', 'ರಾಗಿ', 'ಹತ್ತಿ', 'ತೊಗರಿ'] },
  { id: 'market', label: 'Market & Prices', keywords: ['price', 'mandi', 'market', 'cost', 'rate', 'rupees', 'rate', 'ಬೆಲೆ', 'ಮಾರುಕಟ್ಟೆ', 'ದರ', 'ರೂಪಾಯಿ', 'ಮಾರುಕಟ್ಟೆಯ'] },
  { id: 'weather', label: 'Weather & Water', keywords: ['weather', 'rain', 'water', 'monsoon', 'temperature', 'ಮಳೆ', 'ಹವಾಮಾನ', 'ನೀರು', 'ಬೆಳೆ'] },
  { id: 'fertilizer', label: 'Soil & Fertilizer', keywords: ['fertilizer', 'soil', 'n-p-k', 'urea', 'potash', 'gobbara', 'ಮಣ್ಣು', 'ಗೊಬ್ಬರ', 'ಯೂರಿಯಾ'] }
]

const COMMUNITY_TABS = [
  { id: 'feed',      label: 'Kisan Feed',   icon: MessageSquare },
  { id: 'marketplace', label: 'Buy & Sell', icon: ShoppingCart },
]

export default function Community() {
  const { user } = useUser()
  const { toast } = useToast()
  const navigate = useNavigate()
  const { selectedDistrict } = useDistrict()
  const [activeTab, setActiveTab] = useState<'feed' | 'marketplace'>('feed')
  const [newPostContent, setNewPostContent] = useState('')
  const [isCreatingPost, setIsCreatingPost] = useState(false)
  const [mediaFiles, setMediaFiles] = useState<File[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [searchQuery, setSearchQuery] = useState('')
  const [debouncedQuery, setDebouncedQuery] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const [suggestionsOpen, setSuggestionsOpen] = useState(false)
  const [feedScope, setFeedScope] = useState<'global' | 'local'>('global')
  const [selectedTopic, setSelectedTopic] = useState('all')

  const { posts, loading: isFetchingPosts, refetch: fetchPosts } = useCommunityFeed(selectedTopic === 'all' ? undefined : selectedTopic, feedScope, selectedDistrict)

  const { getRootProps, getInputProps } = useDropzone({
    accept: {
      'image/*': ['.png', '.jpg', '.jpeg', '.gif'],
      'video/*': ['.mp4', '.webm']
    },
    onDrop: (acceptedFiles: File[]) => {
      setMediaFiles([...mediaFiles, ...acceptedFiles])
    }
  })

  // Poll for new posts every 10 seconds
  useEffect(() => {
    const interval = setInterval(fetchPosts, 10000);
    return () => clearInterval(interval);
  }, [fetchPosts]);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setDebouncedQuery(searchQuery.trim())
    }, 300)

    return () => window.clearTimeout(timer)
  }, [searchQuery])

  const escapeRegExp = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')

  const highlightMatch = (text: string, query: string, caseSensitive = false) => {
    if (!query.trim()) return text
    const regex = new RegExp(`(${escapeRegExp(query)})`, caseSensitive ? '' : 'i')
    const parts = text.split(regex)
    return parts.map((part, index) =>
      regex.test(part) ? (
        <mark key={index} className="bg-gold-400 text-earth-main font-bold px-0.5 rounded">
          {part}
        </mark>
      ) : (
        part
      )
    )
  }

  const filteredPosts = useMemo(() => {
    const query = debouncedQuery.toLowerCase()
    return posts
      .filter(post => {
        if (selectedTopic === 'all') return true
        const topicObj = TOPICS.find(t => t.id === selectedTopic)
        if (!topicObj) return true
        const content = ((post.body || post.content || '') + ' ' + (post.location || '')).toLowerCase()
        return topicObj.keywords.some(keyword => content.includes(keyword))
      })
      .filter(post => {
        if (!query) return true
        return (post.body || post.content || '').toLowerCase().includes(query) || 
               (post.user?.username || post.user?.full_name || '').toLowerCase().includes(query)
      })
      .filter(post => {
        if (!filterDate) return true
        if (!post.created_at) return false
        try {
          const postDate = new Date(post.created_at)
          return postDate.toISOString().slice(0, 10) === filterDate
        } catch (e) {
          return false
        }
      })
  }, [posts, selectedDistrict, debouncedQuery, filterDate, feedScope, selectedTopic])

  const handleCreatePost = async () => {
    if (!newPostContent.trim() && mediaFiles.length === 0) return
    setIsLoading(true)
    try {
      const mediaUrls: string[] = []
      if (mediaFiles.length > 0) {
        toast({ title: 'Uploading media...' })
        const urls = await UploadAPI.uploadMultipleMedia(mediaFiles, 'posts')
        mediaUrls.push(...urls)
      }

      await PostsAPI.createPost({
        user_id: user?.id || '',
        body: newPostContent,
        location: selectedDistrict || '',
        images: mediaUrls,
      })

      setNewPostContent('')
      setMediaFiles([])
      setIsCreatingPost(false)
      fetchPosts()
      toast({
        title: 'Post shared',
        description: 'Your post is now visible in the community feed.'
      })
    } catch (error) {
      console.error('Error creating post:', error)
      toast({
        title: 'Could not post',
        description: 'The community feed is temporarily unavailable.',
        variant: 'destructive'
      })
    } finally {
      setIsLoading(false)
    }
  }

  const handleLike = async (postId: string) => {
    if (!user?.id) return;
    try {
      await PostsAPI.toggleLike(postId, user.id);
      fetchPosts()
    } catch (error) {
      console.error('Error toggling like:', error)
    }
  }

  const handleComment = async (postId: string, content: string) => {
    if (!user?.id) return;
    try {
      await PostsAPI.addComment(postId, user.id, content);
      fetchPosts()
      toast({ title: 'Comment added' })
    } catch (error) {
      console.error('Error adding comment:', error)
    }
  }

  const handleDeletePost = async (postId: string) => {
    try {
      await PostsAPI.deletePost(postId)
      fetchPosts()
      toast({ title: 'Post deleted' })
    } catch (error) {
      console.error('Error deleting post:', error)
    }
  }

  return (
    <div className="pt-24 px-4 sm:px-6 lg:px-8 pb-12 max-w-7xl mx-auto animate-fade-in">
      <div className="py-12 px-4 md:px-8 max-w-7xl mx-auto">
        <div className="max-w-5xl mx-auto space-y-8">
            {/* Tab switch bar */}
            <div className="flex gap-2 border-b border-earth-border/40 pb-4 mb-4 select-none">
              {COMMUNITY_TABS.map(tab => {
                const IconComponent = tab.icon;
                const isActive = activeTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={cn(
                      'flex items-center gap-2 px-4 py-2.5 rounded-xl text-xs font-bold uppercase tracking-wider transition-all border',
                      isActive
                        ? 'bg-[#c49a2a] text-[#0f0f0b] border-[#c49a2a] shadow-gold-glow'
                        : 'border-[rgba(255,255,255,0.08)] text-[#a09880] hover:text-[#f0ece0] hover:border-white/10 bg-[#151a18]'
                    )}
                  >
                    <IconComponent size={14} />
                    <span>{tab.label}</span>
                    {tab.id === 'marketplace' && (
                      <span className="ml-2 px-2 py-0.5 bg-yellow-500/20 text-yellow-500 text-[9px] rounded-full">
                        Coming Soon
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            {activeTab === 'feed' ? (
              <>
                <ScrollReveal direction="up" delay={0.1}>
                  <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-8">
                     <div>
                        <h1 className="text-4xl font-black text-gold-100 tracking-tight uppercase">Kisan Feed</h1>
                        <p className="text-gold-100/40 text-xs font-bold uppercase tracking-[0.3em] mt-2">Connect · Share · Learn with farmers near you</p>
                     </div>
                     <Button
                       onClick={() => setIsCreatingPost(true)}
                       className="btn-gold h-14 px-10 shadow-gold-glow group"
                     >
                       <Plus className="h-5 w-5 mr-3 group-hover:rotate-90 transition-transform duration-300" />
                       Share with community
                     </Button>
                  </div>
                </ScrollReveal>

                <ScrollReveal direction="up" delay={0.2}>
                  <Card className="card-premium p-1 border-none shadow-premium bg-earth-elevated/20">
                    <div className="grid grid-cols-1 md:grid-cols-12 gap-1">
                      <div className="md:col-span-7 relative">
                        <Search className="absolute left-6 top-1/2 -translate-y-1/2 h-4 w-4 text-gold-400/40" />
                        <Input
                          value={searchQuery}
                          onChange={(e) => {
                            setSearchQuery(e.target.value)
                            setSuggestionsOpen(true)
                          }}
                          placeholder="FILTER BY KEYWORDS, USERS, OR CROPS..."
                          className="bg-transparent border-none text-gold-100 h-16 rounded-none pl-14 pr-10 text-[10px] font-black uppercase tracking-widest placeholder:text-gold-100/10 focus:ring-0"
                        />
                        {searchQuery && (
                           <button onClick={() => setSearchQuery('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-gold-100/20 hover:text-gold-400">
                              <X size={14} />
                           </button>
                        )}
                      </div>
                      <div className="md:col-span-3 border-t md:border-t-0 md:border-l border-earth-border/50 relative">
                         <Calendar className="absolute left-6 top-1/2 -translate-y-1/2 h-4 w-4 text-gold-400/40" />
                         <Input
                          type="date"
                          value={filterDate}
                          onChange={(e) => setFilterDate(e.target.value)}
                          className="bg-transparent border-none text-gold-100 h-16 rounded-none pl-14 text-[10px] font-black uppercase tracking-widest focus:ring-0 [color-scheme:dark]"
                         />
                      </div>
                      <div className="md:col-span-2 border-t md:border-t-0 md:border-l border-earth-border/50 flex items-center justify-center bg-gold-400/5">
                         <button 
                          onClick={() => setFeedScope(feedScope === 'global' ? 'local' : 'global')}
                          className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-all ${feedScope === 'local' && selectedDistrict ? 'text-gold-400' : 'text-gold-100/20 hover:text-gold-100/40'}`}
                         >
                            <Filter size={12} /> {feedScope === 'local' ? 'Local' : 'Global'}
                         </button>
                      </div>
                    </div>
                  </Card>

                  {selectedDistrict && feedScope === 'local' && (
                     <div className="flex items-center gap-2 mt-4 px-2">
                        <MapPin size={10} className="text-gold-400" />
                        <span className="text-[9px] font-black uppercase tracking-[0.2em] text-gold-100/30">Feed Restricted to district: <span className="text-gold-400">{selectedDistrict}</span></span>
                     </div>
                  )}
                </ScrollReveal>

                {/* Topic Filter Pills */}
                <ScrollReveal direction="up" delay={0.25}>
                  <div className="flex flex-wrap items-center gap-2 pb-2">
                    {TOPICS.map((topic) => (
                      <button
                        key={topic.id}
                        onClick={() => setSelectedTopic(topic.id)}
                        className={`px-4 py-2 rounded-full text-xs font-bold uppercase tracking-wider transition-all duration-300 border ${
                          selectedTopic === topic.id
                            ? 'bg-gold-500 text-earth-main border-gold-500 shadow-gold-glow'
                            : 'bg-earth-card text-gold-100/60 border-earth-border hover:border-gold-500/40 hover:text-gold-100'
                        }`}
                      >
                        {topic.label}
                      </button>
                    ))}
                  </div>
                </ScrollReveal>

                <Dialog open={isCreatingPost} onOpenChange={setIsCreatingPost}>
                  <DialogContent className="bg-earth-elevated border-earth-border text-gold-100 sm:max-w-[500px] p-0 overflow-hidden shadow-2xl">
                    <DialogHeader className="p-8 border-b border-earth-border bg-earth-card">
                      <DialogTitle className="text-2xl font-black tracking-tight text-gold-100 uppercase">Create New Post</DialogTitle>
                    </DialogHeader>
                    <div className="p-8 space-y-8">
                      <Textarea
                        placeholder="Share your harvest updates, questions, or farming tips..."
                        value={newPostContent}
                        onChange={(e) => setNewPostContent(e.target.value)}
                        className="min-h-[150px] bg-earth-main border-earth-border focus:border-gold-400 text-gold-100 rounded-2xl p-6 text-sm placeholder:text-gold-100/10 italic leading-relaxed"
                      />

                      <div
                        {...getRootProps()}
