                        {language === 'kn' ? 'ಪೋಸ್ಟ್ ರಚಿಸಿ' : 'Create Post'}
                      </Button>
                    </CardContent>
                  </Card>
                </ScrollReveal>
              ) : (
                <StaggerContainer staggerDelay={0.1}>
                  {posts.map((post) => (
                    <StaggerItem key={post.id}>
                      <PostCard
