                    <FadeIn delay={0.2}>
                      <div className="flex items-center gap-2 p-2 rounded-lg hover:bg-leaf-50 transition-colors cursor-pointer">
                        <MessageCircle className="h-4 w-4 text-blue-500 animate-pulse-soft" />
